"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[8130],{116(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"blog_job","metadata":{"permalink":"/blog/blog_job","editUrl":"https://github.com/yinxiangkai/Website/tree/main/blog/\u804c\u4e1a/\u6c42\u804c\u6307\u5357.md","source":"@site/blog/\u804c\u4e1a/\u6c42\u804c\u6307\u5357.md","title":"\u6c42\u804c\u8e29\u5751\u6307\u5357","description":"\u672c\u6587\u6863\u7684\u5b9a\u4f4d\u662f\u5c31\u4e1a\u5e38\u8bc6\u666e\u53ca\uff0c\u5e76\u4e0d\u662f\u4ec0\u4e48\u6c42\u804c\u79d8\u7c4d\u3002\u6c42\u804c\u8fc7\u7a0b\u4e2d\u7531\u4e8e\u7f3a\u4e4f\u7ecf\u9a8c\u8d70\u4e86\u975e\u5e38\u591a\u7684\u5f2f\u8def\uff0c\u4e8e\u662f\u5199\u4e0b\u6b64\u6587\u6863\u603b\u7ed3\u7ecf\u9a8c\u6559\u8bad\uff0c\u5e2e\u52a9\u540e\u4eba\u907f\u5f00\u4e00\u4e9b\u5751\u3002\u5f53\u7136\u540e\u6765\u8005\u53ef\u4ee5\u5728\u4e0a\u9762\u4fee\u6539\u3002\u603b\u4f53\u6765\u8bf4\u4e0d\u8981\u6025\uff0c\u867d\u7136\u6211\u5de5\u4f5c\u627e\u7684\u4e0d\u592a\u597d\uff0c\u4f46\u662f\u54b1\u7ec4\u597d\u597d\u51c6\u5907\uff08\u516b\u80a1\u3001\u624b\u6495\u3001\u9879\u76ee\u3001\u5b9e\u4e60\uff09\u627e\u4e2a\u6ee1\u610f\u7684\u5de5\u4f5c\u8fd8\u662f\u5f88\u5bb9\u6613\u7684\uff0c\u6240\u4ee5\u597d\u597d\u51c6\u5907\u5c31\u884c\u4e0d\u7528\u7126\u8651\u3002","date":"2026-03-06T00:00:00.000Z","tags":[{"inline":false,"label":"Career Development","permalink":"/blog/tags/career-development","description":"\u804c\u4e1a\u53d1\u5c55\u76f8\u5173\u7684\u6587\u7ae0"}],"readingTime":23.54,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"\u6c42\u804c\u8e29\u5751\u6307\u5357","slug":"blog_job","date":"2026-03-06T00:00:00.000Z","image":"https://image.qifeng.xyz/202507091105071.svg","hide_table_of_contents":false,"pinned":true,"tags":["\u804c\u4e1a"]},"unlisted":false,"nextItem":{"title":"NVTX","permalink":"/blog/blog_nvtx"}},"content":"\u672c\u6587\u6863\u7684\u5b9a\u4f4d\u662f\u5c31\u4e1a\u5e38\u8bc6\u666e\u53ca\uff0c\u5e76\u4e0d\u662f\u4ec0\u4e48\u6c42\u804c\u79d8\u7c4d\u3002\u6c42\u804c\u8fc7\u7a0b\u4e2d\u7531\u4e8e\u7f3a\u4e4f\u7ecf\u9a8c\u8d70\u4e86\u975e\u5e38\u591a\u7684\u5f2f\u8def\uff0c\u4e8e\u662f\u5199\u4e0b\u6b64\u6587\u6863\u603b\u7ed3\u7ecf\u9a8c\u6559\u8bad\uff0c\u5e2e\u52a9\u540e\u4eba\u907f\u5f00\u4e00\u4e9b\u5751\u3002\u5f53\u7136\u540e\u6765\u8005\u53ef\u4ee5\u5728\u4e0a\u9762\u4fee\u6539\u3002\u603b\u4f53\u6765\u8bf4\u4e0d\u8981\u6025\uff0c\u867d\u7136\u6211\u5de5\u4f5c\u627e\u7684\u4e0d\u592a\u597d\uff0c\u4f46\u662f\u54b1\u7ec4\u597d\u597d\u51c6\u5907\uff08\u516b\u80a1\u3001\u624b\u6495\u3001\u9879\u76ee\u3001\u5b9e\u4e60\uff09\u627e\u4e2a\u6ee1\u610f\u7684\u5de5\u4f5c\u8fd8\u662f\u5f88\u5bb9\u6613\u7684\uff0c\u6240\u4ee5\u597d\u597d\u51c6\u5907\u5c31\u884c\u4e0d\u7528\u7126\u8651\u3002\\n\x3c!-- truncate --\x3e\\n\\n![\u4e0b\u6b21\u8fd8\u586b\u975e\u5e38\u7b80\u5355](https://image.qifeng.xyz/badfd2f9c1ecbe6c88a08655b083e6fe.png)\\n\\n## 1 \u5c31\u4e1a\u65b9\u5411\u7bc7\\n\\n\u6709\u5f88\u591a\u5c31\u4e1a\u65b9\u5411\uff0c\u4e3b\u8981\u5206\u4e3a\u79c1\u4f01\u3001\u56fd\u4f01\u3001\u5916\u4f01\u3001\u4e8b\u4e1a\u5355\u4f4d\u3001\u516c\u52a1\u5458\u3001\u519b\u961f\u3002\\n\\n\u5176\u4e2d\u79c1\u4f01\u4e3b\u8981\u5206\u4e3a\u4e92\u8054\u7f51\u516c\u53f8\u548c\u5236\u9020\u4e1a\u4e24\u5927\u7c7b\u3002\u56fd\u4f01\u4e3b\u8981\u5206\u4e3a\u5e02\u573a\u5316\u56fd\u4f01\u3001\u5784\u65ad\u6027\u56fd\u4f01\u3001\u653f\u7b56\u6027\u56fd\u4f01\u3001\u4ee5\u53ca\u4e00\u4e9b\u519b\u5de5\u9662\u6240\u3002\\n\\n\u5c3d\u91cf\u63d0\u524d\u89c4\u5212\u597d\u9009\u62e9\u65b9\u5411\uff0c\u6bcf\u4e00\u4e2a\u65b9\u5411\u90fd\u6709\u5229\u6709\u5f0a\uff0c\u6700\u5fcc\u8bb3\u7684\u5c31\u662f\u5de6\u53f3\u6447\u6446\u3002\u6309\u7167\u62db\u8058\u5f00\u59cb\u65f6\u95f4\u6bb5\uff0c\u6700\u597d\u662f\u5148\u6295\u4e00\u4e0b\u4e92\u8054\u7f51\u6691\u671f\u5c3d\u53ef\u80fd\u8f6c\u6b63\u62ff\u4e2a\u4fdd\u5e95\uff0c\u7136\u540e\u6839\u636e\u81ea\u5df1\u7684\u804c\u4e1a\u89c4\u5212\u9009\u62e9\u56fd\u4f01\u3001\u4e8b\u4e1a\u5355\u4f4d\u3001\u5f3a\u5ea6\u4f4e\u7684\u4e2d\u5c0f\u5382\u3001\u5916\u4f01\u3002\\n\\n### 1.1 \u4e92\u8054\u7f51\u516c\u53f8\\n\\n\u4e92\u8054\u7f51\u57fa\u672c\u53ef\u4ee5\u5206\u4e3a\u5982\u4e0b\u51e0\u7c7b\uff1a\\n\\n1. \u4e92\u8054\u7f51\u8d44\u672c\u96c6\u56e2\uff1a\u8fd9\u7c7b\u516c\u53f8\u6709\u591a\u9879\u63d0\u4f9b\u73b0\u91d1\u6d41\u7684\u4e3b\u8425\u4e1a\u52a1\uff0c\u540c\u65f6\u4f1a\u6295\u8d44\u5927\u91cf\u5176\u4ed6\u65b9\u5411\u7684\u4e1a\u52a1\uff0c\u6216\u8005\u6536\u8d2d\uff0c\u6216\u8005\u81ea\u5df1\u641e\uff0c\u5f62\u6210\u96c6\u56e2\u5e73\u53f0\u3002\u4f8b\u5982\u963f\u91cc\u3001\u5b57\u8282\u3001\u817e\u8baf\u3001\u767e\u5ea6\u3002\\n2. \u5784\u65ad\u578b\u5782\u7c7b\u516c\u53f8\uff1a\u8fd9\u7c7b\u516c\u53f8\u4e3b\u8981\u4e1a\u52a1\u8fd8\u5c40\u9650\u4e8e\u5355\u4e00\u9886\u57df\uff0c\u4f46\u662f\u5728\u8be5\u9886\u57df\u5df2\u7ecf\u6210\u4e3a\u9f99\u5934\u4f01\u4e1a\u6216\u8005\u7248\u5784\u65ad\u5730\u4f4d\uff0c\u5f00\u59cb\u6269\u5927\u4e1a\u52a1\u8303\u56f4\u3002\u5178\u578b\u4ee3\u8868\u662f\u5c0f\u7ea2\u4e66\u3001\u6ef4\u6ef4\u3001\u7f8e\u56e2\u3001\u4eac\u4e1c\u3001\u62fc\u591a\u591a\u3001\u643a\u7a0b\u3001\u7f51\u6613\u3001\u54d4\u54e9\u54d4\u54e9\u3001\u7c73\u54c8\u6e38\u3001\u8d1d\u58f3\u3001\u5fae\u535a\u3002\\n3. \u4e13\u6ce8\u578b\u5782\u7c7b\u516c\u53f8\uff1a\u8fd9\u7c7b\u516c\u53f8\u4e1a\u52a1\u5c40\u9650\u4e8e\u67d0\u4e00\u9886\u57df\uff0c\u4f8b\u5982 \u867e\u76ae\u3001\u5e0c\u97f3\u3001\u5f97\u7269\u3001\u91d1\u5c71\u529e\u516c\u3001\u79d1\u5927\u8baf\u98de\u3001\u5e06\u8f6f\u3002\\n4. \u79d1\u6280\u72ec\u89d2\u517d\uff1a\u8fd9\u7c7b\u516c\u53f8\u4f1a\u968f\u7740\u5f53\u524d\u6280\u672f\u70ed\u70b9\u800c\u53d8\u52a8\uff0c\u7c7b\u5982CV\u65f6\u4ee3\u7684\u5546\u6c64\u79d1\u6280\u3001\u65f7\u89c6\u79d1\u6280\u3001\u4f9d\u56fe\u79d1\u6280\uff0c\u5230\u73b0\u5728\u7684\u5927\u6a21\u578b\u65f6\u4ee3\u7684\u6708\u4e4b\u6697\u9762\u3001MiniMax\u3001DeepSeek\u3001\u96f6\u4e00\u4e07\u7269\u3001\u767e\u5ddd\u667a\u80fd\u3002\\n5. \u6570\u5b57\u670d\u52a1\u516c\u53f8\uff1a\u53ef\u4ee5\u7b80\u5355\u7684\u7406\u89e3\u6210\u5916\u5305\u516c\u53f8\uff0c\u4f8b\u5982\u8f6f\u901a\u3002\\n\\n### 1.2 \u5236\u9020\u4e1a\\n\\n\u8ba1\u7b97\u673a\u80fd\u53bb\u7684\u5236\u9020\u4e1a\u76ee\u524d\u4e3b\u8981\u4ee5\u901a\u8baf\u3001\u81ea\u52a8\u9a7e\u9a76\u3001\u667a\u80fd\u8bbe\u5907\uff0c\u786c\u4ef6\u539f\u5382\u4e3a\u4e3b\u3002\\n\\n\u901a\u8baf\u516c\u53f8\uff1a\u534e\u4e3a\u6570\u901a\u3001\u4e2d\u5174\u3001TP-Link\u3001\u8054\u6d32\u3002\\n\\n\u81ea\u52a8\u9a7e\u9a76\uff1a\u6bd4\u4e9a\u8fea\u3001\u5353\u9a6d\u3001\u851a\u6765\u3001\u5c0f\u9e4f\u3001\u7406\u60f3\u3001\u767e\u5ea6Apollo\u3001\u5c0f\u9a6c\u667a\u884c\u3001\u5361\u5c14\u52a8\u529b\u3001\u6587\u8fdc\u77e5\u884c\u3001momenta\u3001\u5143\u620e\u8d77\u884c\u3001\u5343\u91cc\u667a\u9a7e\uff0c\u534e\u4e3a\u5f15\u671b(\u5df2\u7ecf\u72ec\u7acb)\u7b49\u3002\\n\\n\u667a\u80fd\u8bbe\u5907\uff1a\u5927\u7586\u3001\u5c0f\u7c73\u3001\u534e\u4e3a\u7ec8\u7aef\u3001vivo\u3001oppo\u3001\u4f20\u97f3\u3001\u8363\u8000\u3001\u6d77\u5c14\u3001\u6d77\u4fe1\u3001\u8054\u5f71\u3001\u6b4c\u5c14\u3001\u8054\u60f3\u3001\u7f8e\u7684\u3001\u8fc8\u745e\u3001\u65b0\u51ef\u6765\u3001\u5b87\u91cf\u6607\u3001\u6d77\u5eb7\u5a01\u89c6\u7b49\u3002\\n\\n\u786c\u4ef6\u539f\u5382\uff1a\u767e\u5ea6\u6606\u4ed1\u82af\u3001\u66e6\u671b\u3001\u6469\u5c14\u7ebf\u7a0b\u3001\u58c1\u4ede\u3001\u4e2d\u79d1\u6d77\u5149\u3001\u4e2d\u79d1\u5bd2\u6b66\u7eaa\u3001\u4e2d\u79d1\u66d9\u5149\u3001\u9ed1\u829d\u9ebb\u3001\u71e7\u539f\u79d1\u6280\u3001\u783a\u7b97\u79d1\u6280\u3001\u5730\u5e73\u7ebf\u3001\u6c90\u66e6\u3001\u5c0f\u9e4f\u82af\u7247\u90e8\u95e8\u3001\u851a\u6765\u82af\u7247\u90e8\u95e8\u3001\u534e\u4e3a\u6d77\u601d\u534a\u5bfc\u4f53\u3001\u957f\u946b\u5b58\u50a8\u3001\u5929\u6570\u667a\u82af\u3001\u5b57\u8282\u82af\u7247\u90e8\u95e8\u3001\u745e\u82af\u5fae\u7b49\u3002\\n\\n\u9700\u8981\u6ce8\u610f\u5f88\u591a\u4f20\u7edf\u5236\u9020\u4e1a\u7684\u4e1a\u52a1\u4e0d\u4f9d\u9760\u8ba1\u7b97\u673a\u8fdb\u884c\u9a71\u52a8\uff0c\u6240\u4ee5\u6709\u5f88\u5927\u7684\u52a8\u529b\u641e\u8ba1\u7b97\u673a\u5185\u5305\u7684\u64cd\u4f5c\u3002\\n\\n### 1.3 \u56fd\u4f01\\n\\n1. \u5784\u65ad\u6027\u56fd\u4f01\uff1a\u7535\u7f51\uff08\u56fd\u7f51\u3001\u5357\u7f51\uff09\u3001\u70df\u8349\u3001\u77f3\u6cb9\uff08\u4e2d\u77f3\u6cb9\u3001\u4e2d\u77f3\u5316\u3001\u4e2d\u6d77\u6cb9)\u3001\u4e94\u5927\u884c(\u5de5\u519c\u4e2d\u5efa\u4ea4)\u7b49\u3002\\n2. \u5e02\u573a\u5316\u56fd\u4f01\uff1a\u8fd0\u8425\u5546\u4e0b\u5c5e\u7684\u79d1\u6280\u5b50\u516c\u53f8\u3001\u53d1\u7535\u4f01\u4e1a\uff08\u534e\u80fd\uff0c\u534e\u7535\u3001\u7535\u6295\u3001\u56fd\u7535\u3001\u5927\u5510\uff09\uff0c\u80a1\u4efd\u94f6\u884c\u3001\u8f66\u4f01\uff08\u5e7f\u6c7d\u3001\u4e00\u6c7d\u3001\u4e0a\u6c7d\uff09\u3002\\n3. \u5730\u65b9\u56fd\u4f01\uff1a\u5c71\u4e1c\u9ad8\u901f\u3001\u9f50\u9c81\u77f3\u5316\u3001\u6052\u4e30\u94f6\u884c\u3001\u5c71\u4e1c\u6e2f\u53e3\u3002\\n4. \u653f\u7b56\u6027\u56fd\u4f01\uff1a\u5546\u98de\u3001\u56fd\u5bb6\u5f00\u53d1\u94f6\u884c\u7b49\u3002\\n5. \u519b\u5de5\u9662\u6240\uff1a\u4e2d\u56fd\u822a\u5929\u79d1\u6280\u96c6\u56e2\u3001\u4e2d\u56fd\u7535\u5b50\u79d1\u6280\u96c6\u56e2\u3001\u4e2d\u56fd\u5175\u5668\u96c6\u56e2\u3001\u4e2d\u56fd\u8239\u8236\u96c6\u56e2\u4e0b\u5c5e\u7814\u7a76\u6240\u3002\u519b\u5de5\u9662\u6240\u51fa\u5dee\u591a\uff0c\u800c\u4e14\u5165\u804c\u540e\u6709\u964d\u85aa\u98ce\u9669\u3002\\n\\n\u8fd9\u4e2a\u5206\u7c7b\u6bd4\u8f83\u6a21\u7cca\uff0c\u4e00\u822c\u56fd\u4f01\u5177\u5907\u591a\u79cd\u5c5e\u6027\uff0c\u540c\u65f6\u5177\u5907\u6570\u91cf\u5e9e\u5927\u7684\u5b50\u516c\u53f8\u548c\u4e1a\u52a1\u90e8\u95e8\uff0c\u9700\u8981\u770b\u5177\u4f53\u90e8\u95e8\u5206\u6790\u3002\u800c\u4e14\u9700\u8981\u6ce8\u610f\u56fd\u4f01\u5b58\u5728\u57fa\u5c42\u8f6e\u5c97\uff0c\u6709\u4e00\u5b9a\u51e0\u7387\u56de\u4e0d\u5230\u539f\u5b9a\u7684\u90e8\u95e8\u3002\u6709\u7684\u56fd\u4f01\u4ec5\u4ec5\u662f\u56fd\u8d44\u63a7\u80a1\u4f46\u662f\u9886\u57df\u4e0d\u6d89\u53ca\u57fa\u7840\u6c11\u751f\u7684\u57fa\u672c\u5f53\u4f5c\u79c1\u4f01\u770b\u5f85\u5c31\u884c\uff08\u8363\u8000\u3001\u65b0\u51ef\u6765\u3001\u6d6a\u6f6e\uff09\u3002\\n\\n## 2 \u65f6\u95f4\u8282\u70b9\u7bc7\\n\\n![\u6c42\u804c\u65f6\u95f4\u7ebf](https://image.qifeng.xyz/e2a7f4b5e04f0b0c50521827660e5b74.svg)\\n\\n### 2.1 \u65e5\u5e38\u5b9e\u4e60\\n\\n\u65e5\u5e38\u5b9e\u4e60\u4e00\u822c\u662f\u7814\u4e8c\u4e0b\u5b66\u671f\u76841-5\u6708\u4efd\u3002\u9700\u8981\u660e\u786e\u65e5\u5e38\u5b9e\u4e60\u4e00\u822c\u6ca1\u6709\u8f6c\u6b63\uff0c\u53ea\u662f\u6691\u671f\u5b9e\u4e60\u7684\u8df3\u677f\u3002\u6240\u4ee5\u4e0d\u4e00\u5b9a\u8981\u5b9e\u4e60\u6ee1\u4e09\u4e2a\u6708\uff0c\u53ef\u4ee5\u9a91\u9a74\u627e\u9a6c\u3002\\n\\n1. \u6709\u4e00\u6bb5\u65e5\u5e38\u5b9e\u4e60\u5bf9\u4e8e\u627e\u6691\u671f\u5b9e\u4e60\u6709\u5e2e\u52a9\u3002\\n2. \u6709\u4e00\u6bb5\u65e5\u5e38\u5b9e\u4e60\uff0c\u6691\u671f\u53ef\u4ee5\u51b2\u5927\u5382\uff0c\u4e0d\u7136\u62ff\u5230\u4e2d\u5c0f\u5382\u7684\u6691\u671f\u53bb\u4e0d\u53bb\u5c31\u6bd4\u8f83\u7ea0\u7ed3\u4e86\u3002\\n3. \u4e0d\u8fc7\u4ece\u5b9e\u9645\u7ecf\u9a8c\u6765\u8bf4\uff0c\u6ca1\u6709\u65e5\u5e38\u627e\u4e00\u4e2a\u4e2d\u5927\u5382\u7684\u6691\u671f\u5b9e\u4e60\u4e5f\u4e0d\u662f\u90a3\u4e48\u96be\uff0c\u6240\u4ee5\u8001\u5e08\u8ba9\u53bb\u5c31\u53bb\uff0c\u4e0d\u8ba9\u53bb\u5c31\u7b97\u4e86\u3002\u597d\u7684\u79d1\u7814\u9879\u76ee\u53ef\u4ee5\u5f25\u8865\u5b9e\u4e60\u7684\u5dee\u8ddd\uff0c\u6709\u7684\u65f6\u5019\u6bd4\u5e72\u6742\u6d3b\u7684\u5b9e\u4e60\u5e2e\u52a9\u66f4\u5927\u4e00\u70b9\u3002\\n4. \u5b9e\u4e60\u53ef\u4ee5\u5e2e\u52a9\u81ea\u5df1\u4e86\u89e3\u516c\u53f8\u548c\u5177\u4f53\u56e2\u961f\u7684\u6c1b\u56f4\uff0c\u540c\u516c\u53f8\u4e0d\u540c\u56e2\u961f\u6c1b\u56f4\u5dee\u8ddd\u5f88\u5927\uff0c\u5c24\u5176\u662f\u5927\u516c\u53f8\u3002\\n5. \u5c3d\u91cf\u627e\u5782\u76f4\u65b9\u5411\u7684\u5b9e\u4e60\u3002\\n\\n### 2.2 \u6691\u671f\u5b9e\u4e60\\n\\n\u6691\u671f\u5b9e\u4e60\u6709\u8f6c\u6b63\u673a\u4f1a\uff0c\u5927\u5382\u62db\u8058\u540d\u989d\u5411\u6691\u671f\u5b9e\u4e60\u8f6c\u6b63\u503e\u659c\uff0c\u79cb\u62db\u57fa\u672c\u6ca1\u6709\u591a\u5c11HC\uff08head count\uff09\u4e86\u3002\u56e0\u6b64\u60f3\u53bb\u4e92\u8054\u7f51\u4e2d\u5927\u5382\u7684\u5c3d\u91cf\u901a\u8fc7\u6691\u671f\u8f6c\u6b63\u7684\u65b9\u5f0f\u3002\u8fd1\u5e74\uff0c\u79cb\u62db\u6709\u4e9b\u516c\u53f8\uff08\u4f8b\u5982\u963f\u91cc\u7cfb\u67d0\u4e9b\u90e8\u95e8\uff09\u90e8\u95e8\u4e0d\u7ed9\u79cb\u62dboffer\u800c\u662f\u7ed9\u5b9e\u4e60offer\uff0c\u8fd8\u662f\u8981\u53bb\u5b9e\u4e60\uff0c\u8d70\u8f6c\u6b63\u6d41\u7a0b\u3002\u6240\u4ee5\u6691\u671f\u5b9e\u4e60\u8f6c\u6b63\u53ef\u4ee5\u7701\u5f88\u591a\u4e8b\u60c5\uff0c\u4e5f\u80fd\u7a7a\u51fa\u65f6\u95f4\u6765\u51c6\u5907\u56fd\u592e\u4f01\u548c\u8003\u516c\u3002\\n\\n\u6691\u671f\u5b9e\u4e60\u8981\u6ce8\u610f\u5206\u8fa8\u6709\u65e0\u8f6c\u6b63HC\u3002\u5f88\u591a\u5236\u9020\u4e1a\u516c\u53f8\u7684\u6691\u671f\u5b9e\u4e60\u662f\u6ca1\u6709\u8f6c\u6b63\u7684\uff0c\u5b57\u8282\u4e5f\u9700\u8981\u6ce8\u610f\uff0c\u6211\u8ba4\u8bc6\u7684\u5b57\u8282\u5b9e\u4e60\u751f\uff083\u4e2a\uff09\u90fd\u6ca1\u8f6c\u6b63\u3002\u534e\u4e3a\u53ea\u6709\u4f18\u79c0\u5b9e\u4e60\u751f\u53ef\u4ee5\u76f4\u63a5\u4e3b\u7ba1\u9762\uff0c\u4f18\u79c0\u6bd5\u4e1a\u751f\u5360\u6bd4\u4e0d\u9ad8\uff0c\u6027\u4ef7\u6bd4\u6781\u4f4e\u3002\u4e0d\u8fc7\u5c31\u7b97\u4e0d\u53bb\u534e\u4e3a\u5b9e\u4e60\u4e5f\u5efa\u8bae\u8003\u4e00\u4e0b\u534e\u4e3a\u7684\u6691\u671f\u7b14\u8bd5\uff0c\u53ef\u4ee5\u79cb\u62db\u590d\u7528\uff0c\u589e\u52a0\u4e00\u6b21\u673a\u4f1a\u3002\\n\\n\u5b9e\u4e60\u671f\u95f4\u6709\u5f88\u5927\u6982\u7387\u662f\u5e72\u6742\u6d3b\uff0c\u6240\u4ee5\u9700\u8981\u81ea\u5df1\u770b\u6587\u6863\uff0c\u68b3\u7406\u9879\u76ee\uff08\u9762\u8bd5\u7684\u65f6\u5019\u80fd\u5439\uff09\uff0c\u4e86\u89e3mentor \u7684\u5de5\u4f5c\uff0c\u719f\u6089\u516c\u53f8\u73af\u5883\uff0c\u4e86\u89e3\u5404\u4e2a\u90e8\u95e8\u7684\u804c\u8d23\uff0c\u53d1\u5c55\u524d\u666f\u3002\u4e86\u89e3\u54ea\u4e9b\u90e8\u95e8\u662f\u6838\u5fc3\u90e8\u95e8\uff0c\u54ea\u4e9b\u662f\u8fb9\u7f18\u90e8\u95e8\u3002\\n\\n\u6700\u540e\u5f3a\u8c03\u4e00\u70b9\u5b9e\u4e60\u662f\u624b\u6bb5\u4e0d\u662f\u76ee\u7684\u3002\u4e0d\u662f\u6240\u6709\u7684\u5b9e\u4e60\u90fd\u503c\u5f97\u53bb\uff0c\u5c3d\u91cf\u53bb\u80cc\u4e66\u597d\u7684\u4f01\u4e1a\u3002\u4ee52026\u5c4a\u7684\u7ecf\u9a8c\u6765\u770b\uff0c\u54b1\u5b66\u6821\u627e\u4e00\u4e2a\u4e2d\u5927\u5382\u6691\u671f\u8fd8\u662f\u6bd4\u8f83\u5bb9\u6613\u7684\uff0c\u8ba4\u771f\u627e\u7684\u57fa\u672c\u90fd\u627e\u5230\u4e86\u4e2d\u5927\u5382\uff08\u7f8e\u56e2\u3001\u5b57\u8282\u3001\u963f\u91cc\u3001\u817e\u8baf\u3001\u4eac\u4e1c\u3001\u534e\u4e3a\u3001\u8682\u8681\uff09\u3002\u5f88\u591a\u4eba\u662f\u4e94\u516d\u6708\u4efd\u624d\u62ff\u5230\u7684\uff0c\u6240\u4ee5\u522b\u592a\u7740\u6025\u3002\\n\\n### 2.3 \u79cb\u62db\\n\\n\u79cb\u62db\u63d0\u524d\u6279\uff0c\u4e3b\u8981\u662f\u4eba\u624d\u8ba1\u5212\uff0c\u5f85\u9047\u5f88\u597d\uff0c\u4e00\u822c\u7ed3\u679c\u4e0d\u5f71\u54cd\u6b63\u5f0f\u6279\u5efa\u8bae\u8bd5\u8bd5\u3002\\n\\n\u5bf9\u4e8e\u4e92\u8054\u7f51\u4f01\u4e1a\u548c\u90e8\u5206\u5934\u90e8\u5236\u9020\u4e1a\u4f01\u4e1a\u5df2\u7ecf\u4e0d\u662f\u91d1\u4e5d\u94f6\u5341\u4e86\uff0c\u4ece\u4e03\u6708\u4efd\u5c31\u5e94\u8be5\u5f00\u59cb\u4e86\uff0c\u5f88\u591a\u516c\u53f8\u516b\u6708\u4efd\u5c31\u53ef\u4ee5\u8d70\u5b8c\u6d41\u7a0b\u4e86\u3002\u4e5d\u6708\u4efd\u4e00\u822c\u662f\u6700\u96be\u53d7\u7684\u4e00\u4e2a\u6708\uff0c\u4f1a\u8fdb\u884c\u5927\u91cf\u7684\u7b14\u8bd5\u4e0e\u9762\u8bd5\uff0c\u4f46\u662f\u4e00\u822c\u90fd\u4f1a\u88ab\u6ce1\u6c60\u5b50\u6a2a\u5411\u5bf9\u6bd4\u3002\u5341\u6708\u4efd\u56fd\u5e86\u540e\u5f00\u59cb\u96c6\u4e2d\u8c08\u85aa\uff0c\u8fd9\u65f6\u5019\u4f1a\u6709\u5f88\u591a\u4eba\u4f1a\u62ff\u5230\u4e00\u4e9b\u4e0d\u592a\u6ee1\u610f\u7684offer\u3002\u5341\u4e00\u5230\u5341\u4e8c\u6708\u4efd\uff0c\u5927\u90e8\u5206\u4eba\u90fd\u662f\u8fd9\u4e2a\u65f6\u5019\u5f00\u5956\uff0c\u5927\u91cfoffer\u5f00\u59cb\u91ca\u653e\uff0c\u5f00\u59cb\u6361\u6f0f\u3002\\n\\n\u56fd\u4f01\u901a\u5e38\u8fd8\u662f\u4e5d\u6708\u4e0b\u5f00\u59cb\u5ba3\u8bb2\u8d70\u62db\u8058\u6d41\u7a0b\u300211-12\u6708\u4efd\u624d\u5f00\u59cb\u5f00\u5956\u4f53\u68c0\u6d41\u7a0b\u3002\u90e8\u5206\u56fd\u4f01\u53ea\u5904\u7406\u7ebf\u4e0b\u6295\u9012\u7684\u7b80\u5386\uff0c\u4f8b\u5982\u4e2d\u8f66\u3002\\n\\n### 2.4 \u6625\u62db\\n\\n\u6625\u62db\u673a\u4f1a\u4e5f\u662f\u5f88\u591a\u7684\uff0c\u6240\u4ee5\u4e0d\u8981\u592a\u65e9\u6446\u70c2\\n\\n## 3 \u5c97\u4f4d\u6295\u9012\\n\\n### 3.1 \u6295\u9012\\n\\n\u4e2d\u5c0f\u5382\u548c\u5236\u9020\u4e1a\u7684\u79cb\u62db\u5c97\u4f4d\u4e00\u822c\u6bd4\u8f83\u7b3c\u7edf\uff0c\u591a\u4e2a\u90e8\u95e8\u7684\u5c97\u4f4d\u4f1a\u6253\u5305\u6210\u4e00\u4e2a\u5c97\u4f4d\uff0c\u6240\u4ee5JD\uff08job description\uff09\u8981\u6c42\u5f88\u9ad8\uff0c\u5176\u5b9e\u8fd9\u662f\u591a\u4e2a\u5c97\u4f4d\u6c47\u603b\u7684\u8981\u6c42\u3002\u5728\u5b98\u7f51\u6295\u9012\u524d\u53ef\u4ee5\u5148\u53bbBoss\u76f4\u8058\u3001\u5c0f\u7ea2\u4e66\u3001\u725b\u5ba2\u4e0a\u627e\u4e00\u4e0b\u5177\u4f53\u90e8\u95e8\u7684\u62db\u8058\u4eba\u5458\uff0c\u8fd9\u6837\u4f1a\u66f4\u5bf9\u53e3\u4e00\u4e9b\u3002\u540c\u65f6\u5b98\u7f51\u6d41\u7a0b\u6302\u4e86\u4e4b\u540e\uff0c\u53ef\u4ee5\u53bb\u627e\u5177\u4f53\u4e1a\u52a1\u90e8\u95e8\u7684HR\u635e\u4e00\u635e\u3002\u53d1\u52a8\u4e00\u4e0b\u81ea\u5df1\u4eba\u8109\uff0c\u591a\u627e\u627e\u4eba\uff0c\u53ef\u4ee5\u4e86\u89e3\u5c97\u4f4d\u4fe1\u606f\u548chc\u6570\u91cf\u3002\\n\\n\u8981\u5c0f\u5fc3\u592a\u8fc7\u70ed\u60c5\u7684HR\uff0c\u5c24\u5176\u662f\u534e\u4e3a\u7cfb\uff08\u534e\u4e3a\u3001\u5f15\u671b\u3001\u65b0\u51ef\u6765\u3001\u5b87\u91cf\u6607\uff09\uff0c\u534e\u4e3a\u7cfb\u7ed9\u4e86\u7b80\u5386\u53f7\u6216\u8005\u586b\u4e86\u5185\u63a8\u7801\uff0c\u4f1a\u88ab\u5b50\u90e8\u95e8\u9501\u7b80\u5386\u3002\u4e00\u5b9a\u8981\u60f3\u597d\u4e86\u518d\u7ed9\u7b80\u5386\u53f7\u6216\u8005\u586b\u5185\u63a8\u7801\uff0c\u534e\u4e3a\u662f\u6765\u5b66\u6821\u5ba3\u8bb2\u540e\u5f00\u59cb\u7b5b\u7b80\u5386\u3002\u5c71\u5927\u5728\u6c5f\u5c71\u5e73\u53f0\uff08\u534e\u4e3a\u6c5f\u82cf\u5c71\u4e1c\u62db\u8058\uff0c\u5173\u6ce8\u516c\u4f17\u53f7\uff09\u3002\u9700\u8981\u660e\u786e\u4e00\u70b9\u534e\u4e3a\u7684\u5f88\u591aHR \u4e0d\u662f\u771f\u7684HR \u800c\u662f\u4e1a\u52a1\u5c97\uff0c\u4e00\u822c\u79f0\u4e3a\u63a5\u53e3\u4eba\u3002\u8fd9\u4e9b\u4eba\u662f\u6ca1\u6709HR\u7684\u6743\u9650\u7684\u3002\\n\\n\u9700\u8981\u6ce8\u610f\u4e00\u70b9\u5f88\u591a\u516c\u53f8\u6295\u9012\u5c97\u4f4d\u662f\u6709\u4e0a\u9650\u7684\u4e0d\u5efa\u8bae\u4e00\u6b21\u6027\u6295\u9012\u5b8c\uff0c\u6700\u597d\u7559\u4e00\u4e2a\u5c97\u4f4d\u7a7a\u7f3a\uff0c\u9632\u6b62\u540e\u7eed\u51fa\u73b0\u66f4\u9002\u5408\u7684\u5c97\u4f4d\uff0c\u6216\u8005\u8865\u5f55\u3002\\n\\n### 3.2 \u9009\u62e9\\n\\n\u4eba\u751f\u662f\u65f7\u91ce\uff0c\u4e0d\u662f\u8f68\u9053\u3002\u4e0d\u8981\u7ed9\u81ea\u5df1\u589e\u52a0\u592a\u591a\u7684\u675f\u7f1a\u3002\\n\\n1. \u65b9\u5411\u6d01\u7656\uff1a\u6709\u4e9b\u5c97\u4f4d\u8fdb\u5927\u5382\u5c31\u662f\u5bb9\u6613\uff0c\u800c\u4e14\u4e5f\u66f4\u5bb9\u6613\u4fdd\u5e95\u3002\u65b9\u5411\u662f\u7531\u4f01\u4e1a\u8d4b\u4e88\u4ef7\u503c\u7684\uff0c\u8fdb\u4e00\u4e2a\u5927\u516c\u53f8\u5bf9\u540e\u7eed\u53d1\u5c55\u66f4\u6709\u5229\u3002\u6240\u4ee5\u53ef\u80fd\u653e\u5f03\u7814\u7a76\u751f\u7684\u7814\u7a76\u9886\u57df\u6362\u4e00\u4e2a\u5927\u4f17\u5316\u7684\u8d5b\u9053\u4f1a\u66f4\u597d\u4e00\u4e9b\u3002\u4f8b\u5982\u540e\u7aef\u5f00\u53d1+agent\uff08AI\uff09\uff0c\u65e2\u53ef\u4ee5\u8d70\u4e92\u8054\u7f51\u4e5f\u53ef\u4ee5\u8d70\u56fd\u4f01\u94f6\u884c\u3002\u540c\u65f6\u9700\u8981\u8003\u8651\u662f\u5426\u771f\u7684\u60f3\u505a\u6280\u672f\u5c97\u800c\u4e0d\u662f\u804c\u80fd\u5c97\u3002\\n2. \u4e1a\u52a1\u9009\u62e9\uff1a\u5c31\u4e1a\u91cd\u70b9\u5728\u4e8e\u4e1a\u52a1\u65b9\u5411\u3002\u4ee5C++\u4e3a\u4f8b\uff0cC++\u53ea\u662f\u4e00\u4e2a\u901a\u7528\u6280\u672f\uff0c\u5177\u4f53\u7684\u4e1a\u52a1\u5206\u4e3a\u670d\u52a1\u5668\u540e\u7aef\u3001\u5ba2\u6237\u7aef\u3001\u56fe\u50cf\u3001\u97f3\u9891\u3001\u81ea\u52a8\u9a7e\u9a76\u3001\u5177\u8eab\u667a\u80fd\u3001AI infra\u3001\u5d4c\u5165\u5f0f\u3002\u5927\u5bb6\u5c06Java\u89c6\u4e3a\u5355\u72ec\u7684\u65b9\u5411\u662f\u56e0\u4e3a\u5176\u4e0e\u540e\u7aef\u9ad8\u5ea6\u7ed1\u5b9a\u4e86\u3002\u9762\u8bd5\u4e3b\u8981\u62f7\u6253\u5b9e\u4e60\u3001\u9879\u76ee\u3001\u4e1a\u52a1\uff0c\u516b\u80a1\u548c\u624b\u6495\u4ee3\u7801\u3002\u660e\u786e\u81ea\u5df1\u60f3\u8981\u505a\u4ec0\u4e48\u4e1a\u52a1\uff0c\u4f20\u7edf\u4e1a\u52a1\u7ade\u4e89\u8005\u591a\uff0c\u4f46\u662f\u5c97\u4f4d\u591a\u3002\u65b0\u5174\u4e1a\u52a1\u85aa\u8d44\u9ad8\uff0c\u8981\u6c42\u9ad8\uff0c\u5c97\u4f4d\u5c11\u3002\u5927\u5382\u57fa\u672c\u90fd\u662f\u5b9a\u7ea7\u5b9a\u85aa\u65b9\u5411\u5bf9\u4e8e\u5355\u7eaf\u7684\u6536\u5165\u800c\u8a00\u5f71\u54cd\u4e0d\u5927\u3002\\n3. \u79d1\u7814\uff1a\u54b1\u7ec4\u90e8\u5206\u7814\u7a76\u65b9\u5411\u5c31\u4e1a\u4e5f\u8fd8\u884c\uff0c\u76ee\u524d\u4e5f\u5728\u5411\u5927\u6a21\u578b\u53d1\u5c55\u3002\u968f\u7740\u56fd\u5185\u672c\u79d1\u6559\u80b2\u6c34\u5e73\u7684\u63d0\u5347\uff0c\u597d\u7684\u4f01\u4e1a\u5df2\u7ecf\u5f00\u59cb\u8981\u6c42\u7814\u7a76\u751f\u771f\u7684\u5177\u5907\u7814\u7a76\u751f\u7684\u80fd\u529b\u4e86\uff0c\u4e0d\u518d\u662f\u4ee5\u524d\u5f53\u4f5c\u5927\u53f7\u672c\u79d1\u751f\u7528\u4e86\u3002\u901a\u8fc7\u7ec4\u5185\u7684\u9879\u76ee\u53bb\u5b66\u4e60\u76f8\u5173\u6280\u672f\u6808\uff0c\u7136\u540e\u81ea\u5df1\u53bb\u8865\u9f50\u7406\u8bba\u57fa\u7840\uff0c\u4e1a\u52a1\u6280\u672f\u6808\u3001\u76f8\u5173\u9879\u76ee\u3001\u5782\u7c7b\u5b9e\u4e60\u3002\\n4. \u516c\u53f8\uff1a\u4e92\u8054\u7f51\u5927\u5382\u5e76\u4e0d\u9002\u5408\u6240\u6709\u4eba\uff0c\u4f46\u662f\u53bb\u5b9e\u4e60\u4f53\u9a8c\u4e00\u4e0b\u662f\u53ef\u4ee5\u7684\uff0c\u5982\u679c\u80fd\u8f6c\u6b63\u62ff\u4e2a\u4fdd\u5e95\u4e5f\u53ef\u4ee5\u51b2\u5176\u4ed6\u65b9\u5411\u3002\u6709\u7684\u4e2d\u5c0f\u516c\u53f8\u53cd\u800c\u6c1b\u56f4\u798f\u5229\u4f1a\u597d\u5f88\u591a\u3002\u5c3d\u91cf\u7ed9\u81ea\u5df1\u627e\u4e2a\u9ad8\u8d77\u70b9\u7684\u4f01\u4e1a\uff0c\u5f80\u4e0b\u517c\u5bb9\u5bb9\u6613\uff0c\u4f46\u662f\u5f80\u4e0a\u722c\u5c31\u4e0d\u662f\u90a3\u4e48\u5bb9\u6613\u4e86\u3002\\n5. \u57ce\u5e02\uff1a\u4e0d\u540c\u57ce\u5e02\u7684\u4f01\u4e1a\u98ce\u6c14\u662f\u4e0d\u4e00\u6837\u7684\uff0c\u4f8b\u5982\u9752\u5c9b\u8fd9\u8fb9\u5927\u591a\u6570\u4f01\u4e1a\u90fd\u662f\u5355\u4f11\u3002\u968f\u7740\u7ecf\u6d4e\u53d1\u5c55\uff0c\u4ea7\u4e1a\u79ef\u805a\u6548\u5e94\u5f88\u660e\u663e\uff0c\u5c3d\u91cf\u9009\u62e9\u4ea7\u4e1a\u4e2d\u5fc3\u57ce\u5e02\uff0c\u4f8b\u5982\u4e92\u8054\u7f51\u7684\u5317\u4eac\u3001\u4e0a\u6d77\u3001\u676d\u5dde\uff0c\u81f3\u5c11\u8df3\u69fd\u5bb9\u6613\u4e0d\u7528\u6362\u57ce\u5e02\u3002\u897f\u5b89\u3001\u6b66\u6c49\u3001\u5357\u4eac\u3001\u6210\u90fd\u8fd9\u79cd\u9ad8\u6821\u624e\u5806\u7684\u4e8c\u7ebf\u57ce\u5e02\uff0c\u5c31\u4e1a\u6c1b\u56f4\u5176\u5b9e\u4e0d\u662f\u5f88\u597d\uff0c\u5206\u516c\u53f8\u548c\u5916\u5305\u516c\u53f8\u6bd4\u8f83\u591a\u3002\u5317\u4eac\u516c\u53f8\u591a\u5c97\u4f4d\u591a\u85aa\u8d44\u9ad8\u3001\u5e78\u798f\u611f\u4f4e\uff1b\u4e0a\u6d77\u662f\u96c6\u6210\u7535\u8def\u4e2d\u5fc3\uff0c\u4f53\u7cfb\u7ed3\u6784\u76f8\u5173\u5c97\u4f4d\u591a\uff0c\u793e\u4f1a\u4e3b\u4e49\u6c1b\u56f4\u6d53\u539a\uff0c\u6d88\u8d39\u9ad8\uff1b\u676d\u5dde\u963f\u91cc\u7cfb\u4e3a\u4e3b\uff0c\u521b\u4e1a\u516c\u53f8\u591a\uff1b\u957f\u6c99\uff0c\u786c\u4ef6\u516c\u53f8\u591a\u4e00\u70b9\uff1b\u6df1\u5733\u5236\u9020\u4e1a\u53d1\u8fbe\uff0c\u8f6f\u786c\u7ed3\u5408\u7684\u4ea7\u4e1a\u591a\uff1b\u5e7f\u5dde\u5f3a\u5ea6\u751f\u6d3b\u6210\u672c\u4f1a\u4f4e\u4e00\u4e9b\uff0c\u4f46\u662f\u85aa\u8d44\u76f8\u6bd4\u5176\u4ed6\u4e00\u7ebf\u57ce\u5e02\u85aa\u8d44\u504f\u4f4e\uff0c\u672c\u8d28\u4e0a\u662f\u4e00\u4e2a\u52a0\u5f3a\u7248\u7684\u7701\u4f1a\u57ce\u5e02\u3002\\n\\n## 4 HR\u8c08\u5224\\n\\n### 4.1 \u5f00\u5956\u6d41\u7a0b\\n\\n\u6709\u7684\u516c\u53f8\u6ca1\u6709HR\u9762\uff0c\u6709\u7684\u516c\u53f8HR\u9762\u8d70\u8fc7\u573a\uff0c\u6709\u7684\u4f1a\u6dd8\u6c70\u3002\u4e00\u822cHR\u9762\u4e0d\u4f1a\u8c08\u85aa\uff0c\u53ea\u662f\u4e86\u89e3\u4e00\u4e0b\u4f60\u7684offer \u60c5\u51b5\u548c\u9884\u671f\u85aa\u8d44\u3002\u7136\u540e\u6ce1\u6c60\u5b50\uff08\u6a2a\u5411\u5bf9\u6bd4\uff0c\u9762\u8bd5\u5b8c\u540e\u6839\u636e\u7b14\u8bd5\u9762\u8bd5\u8868\u73b0\u6392\u5e8f\uff09\u3002\u4f46\u662f\u4e00\u90e8\u5206\u516c\u53f8\u662f\u5f00\u5956\u5f00\u51fa\u6765\u4e86\u624d\u4f1a\u6709HR\u9762\u3002\\n\\n\u6839\u636e\u6392\u5e8f\u987a\u5e8f\u4f9d\u6b21\u8054\u7cfb\u9762\u8bd5\u8005\uff0c\u6253\u7535\u8bdd\u6c9f\u901a\uff08oc\uff0coffer call\uff09\uff0c\u4e3b\u8981\u662f\u786e\u8ba4\u85aa\u8d44\u5f85\u9047\u3002\u5927\u90e8\u5206\u516c\u53f8\u8fd9\u65f6\u5019\u4e0d\u662f\u6b63\u5f0foffer\u3002\u4f60\u540c\u610f\u85aa\u8d44\u5f85\u9047\u4e86\uff0c\u518d\u8d70\u516c\u53f8\u5ba1\u6279\u624d\u4f1a\u7ed9\u6b63\u5f0foffer\u3002\u5bf9\u85aa\u8d44\u4e0d\u6ee1\u610f\u53ef\u4ee5\u95ee\u95ee\u80fd\u4e0d\u80fd\u6da8\u3002\u8fd8\u6709\u4e00\u90e8\u5206\u516c\u53f8\u662f\u5ba1\u6279\u5b8c\u4e86\u76f4\u63a5\u53d1offer \u8fd9\u79cd\u57fa\u672c\u5c31\u662f\u6253\u5305\u4ef7\u6ca1\u5f97\u8c08\\n\\n\u6b63\u5f0foffer \u4f1a\u7ed9\u4e00\u6bb5\u65f6\u95f4\u8003\u8651\uff0c\u63a5\u4e86\u4e4b\u540e\u5c31\u662f\u8d70\u4e09\u65b9\u534f\u8bae\u3002\\n\\n### 4.2 \u85aa\u8d44\u6784\u6210\\n\\n**\u7a0e\u524d\u6708\u85aa\uff1a**\u5e95\u85aa+\u7ee9\u6548+\u5956\u91d1+\u52a0\u73ed+\u8865\u52a9\uff08\u4ea4\u901a\u3001\u9910\u996e\u3001\u4f4f\u5bbf\u8865\u52a9\uff09+\u5176\u4ed6\u798f\u5229\u3002\\n\\n**\u5230\u624b\u6708\u85aa\uff1a**\u7a0e\u524d-\u4e94\u9669\u4e00\u91d1\u4e2a\u4eba\u7f34\u7eb3\u90e8\u5206-\u4e2a\u4eba\u6240\u5f97\u7a0e\uff08\u4e94\u9669\u4e00\u91d1\u5168\u989d\u4ece\u7a0e\u524d\u6263\u9664\uff0c\u4e0d\u7f34\u4e2a\u4eba\u6240\u5f97\u7a0e\uff09\u3002\\n\\n**\u5e74\u7ec8\u5956/13\u300114\u85aa\uff1a**\u5982\u679c\u5728\u5408\u540c\u4e2d\u5199\u660e\u4e86\u4e00\u5e74\u662f13\u85aa\u4ee5\u4e0a\uff0c\u53ef\u4ee5\u89c6\u4e3a\u57fa\u672c\u5de5\u8d44\uff0c\u5426\u5219\u5c31\u662f\u5e74\u7ec8\u5956\uff0c\u5e74\u7ec8\u5956\u6709\u6d6e\u52a8\uff0c\u548c\u7ee9\u6548\u6302\u94a9\u3002\u7ee9\u6548\u4e00\u822c\u548c\u516c\u53f8\u8425\u6536\u3001\u90e8\u95e8\u7ee9\u6548\u3001\u4e2a\u4eba\u7ee9\u6548\u4e09\u90e8\u5206\u76f8\u5173\\n\\n\u9700\u8981\u6ce8\u610f\u90e8\u5206\u4f01\u4e1a\uff08\u56fd\u4f01\uff09\u4f1a\u5c06\u5730\u65b9\u653f\u5e9c\u7684\u4eba\u624d\u8865\u8d34\uff0c\u516c\u79ef\u91d1\u7b97\u8fdb\u603b\u5305\uff0c\u4e00\u5b9a\u8981\u5c0f\u5fc3\u3002\\n\\n### 4.3 \u798f\u5229\u5f85\u9047\\n\\n**\u4e94\u9669\u4e00\u91d1\uff1a**\\n\\n\u517b\u8001\u4fdd\u9669\uff08\u4f01\u4e1a\uff1a20%\uff0c\u4e2a\u4eba8%\uff09\u3001\u533b\u7597\u4fdd\u9669\uff0810%\uff0c2%\uff09\u3001\u751f\u80b2\u4fdd\u9669\uff080.8%\uff0c0%\uff09\u3001\u5de5\u4f24\u4fdd\u9669\uff080.2%-1.4%\uff0c0%\uff09\u3001\u5931\u4e1a\u4fdd\u9669\uff082%\uff0c1%\uff09\u3002\u5176\u4e2d\u5de5\u4f24\u4fdd\u9669\u7f34\u7eb3\u6bd4\u4f8b\u4f1a\u6709\u6d6e\u52a8\uff0c\u5176\u4ed6\u7684\u662f\u56fa\u5b9a\u6bd4\u4f8b\u3002\u53ef\u4ee5\u76f4\u63a5\u89c6\u4e3a\u4e00\u79cd\u7a0e\u3002\\n\\n\u4f4f\u623f\u516c\u79ef\u91d1\uff0c\u5927\u90e8\u5206\u5730\u533a\u7684\u4f4f\u623f\u516c\u79ef\u91d1\u53ef\u4ee5\u63d0\u73b0\uff0c\u6240\u4ee5\u6bd4\u8f83\u91cd\u8981\uff1a\\n\\n1. \u7f34\u7eb3\u57fa\u6570\uff1a\u8fd9\u4e2a\u8981\u95ee\u6e05\u662f\uff1a\u5b9e\u9645\u5de5\u8d44/\u5f53\u5730\u6700\u4f4e\u57fa\u6570/\u5f53\u5730\u6700\u9ad8\u57fa\u6570\u3002\\n2. \u7f34\u7eb3\u6bd4\u4f8b\uff1a5~12%\u6d6e\u52a8\uff0c\u4f01\u4e1a\u548c\u4e2a\u4eba\u5bf9\u7b49\u6bd4\u4f8b\uff0c\u7531\u4e8e\u53ef\u4ee5\u63d0\u73b0\uff08\u770b\u5730\u65b9\u653f\u7b56\uff09\uff0c\u56e0\u6b64\u6bd4\u4f8b\u8d8a\u591a\u5230\u624b\u8d8a\u591a\u3002\u800c\u4e14\u4f4f\u623f\u516c\u79ef\u91d1\u5168\u989d\u4ece\u7a0e\u524d\u6263\u9664\uff0c\u4e92\u8054\u7f51\u57fa\u672c\u662f12%\uff0c\u5236\u9020\u4e1a\u4e00\u822c\u8fbe\u4e0d\u5230\uff0c\u4f8b\u5982\u534e\u4e3a5%\u3002\\n\\n**\u4e03\u9669\u4e8c\u91d1\uff1a**\\n\\n\u4e94\u9669\u4e00\u91d1+\u8865\u5145\u533b\u7597\u4fdd\u9669+\u957f\u671f\u62a4\u7406\u4fdd\u9669+\u4f01\u4e1a\u5e74\u91d1\u3002\uff08\u90e8\u5206\u592e\u56fd\u4f01+\u67d0\u4e9b\u9ad8\u5229\u6da6\u4f01\u4e1a\uff09\\n\\n### 4.4 \u8c08\u85aa\\n\\n\u4f01\u4e1a\u4f1a\u7ed9\u5b9a\u85aa\u8d44\u8303\u56f4\uff08boss\u76f4\u8058\u6216\u8005offershow\uff09\uff0c\u4e0d\u8981\u8f7b\u6613\u8981\u8d85\u8fc7\u4e0a\u9650\u7684\u85aa\u8d44\uff0c\u9664\u975e\u4f60\u6709\u5176\u4ed6offer\u6765\u62ac\u85aa\u3002 \u6ce8\u610f\u8c08\u85aa\u8fc7\u7a0b\u4e2d\u7ed9\u4e1a\u52a1\u90e8\u95e8\u662f\u53ef\u80fd\u7684\u76df\u53cb\uff0c\u53ef\u4ee5\u54a8\u8be2\u4e0b\u85aa\u8d44\u5efa\u8bae\u3002\\n\\n**\u5173\u6ce8\u70b9\uff1a**\\n\\n1. \u8bd5\u7528\u671f\u65f6\u5e38\u3001\u662f\u5426\u5168\u85aa\uff0c\u65b0\u4eba\u57f9\u517b\u5236\u5ea6\uff0c\u8f6c\u6b63\u6807\u51c6\u3002\\n2. \u53d1\u85aa\u65e5\uff08\u5f53\u6708\u53d1\u6700\u826f\u5fc3\uff0c\u4e0b\u670815\u53f7\u524d\u53d1\u7b97\u6b63\u5e38\u3001\u4e4b\u540e\u53d1\u826f\u5fc3\u5927\u5927\u7684\u574f\uff09\u3002\\n3. \u516c\u79ef\u91d1\u7f34\u7eb3\u57fa\u6570\u548c\u6bd4\u4f8b\uff0c\u4e3b\u8981\u662f\u57fa\u6570\uff0c\u662f\u6309\u7167\u5e95\u85aa\u7b97\u8fd8\u662f\u5e95\u85aa\u52a0\u7ee9\u6548\uff0c\u6216\u8005\u5f53\u5730\u6700\u9ad8\u4e0a\u9650\u3002\\n4. \u7ee9\u6548\u3001\u8c03\u85aa\u3001\u5e74\u7ec8\u5956\u3001\u8003\u6838\u5468\u671f\u3002\uff08\u90e8\u5206\u4f01\u4e1a\u7b2c\u4e00\u5e74\u65e0\u5e74\u7ec8\u5956\uff09\\n5. \u5e74\u5047\u3001\u5047\u65e5\u798f\u5229\u3002\uff08\u7b2c\u4e00\u5e74\u5e74\u5047\u5929\u6570\uff09\\n6. \u8865\u52a9\u3001\u98df\u5802\u3001\u5bbf\u820d\u3001\u8003\u52e4\uff08\u4e0d\u6253\u5361\u4e0d\u4e00\u5b9a\u662f\u597d\u4e8b\uff09\u3002\\n7. \u662f\u5426\u9700\u8981\u63d0\u524d\u5b9e\u4e60\u3002\\n8. \u4ec0\u4e48\u65f6\u5019\u7b7e\u5408\u540c\u3002\\n\\n**\u96f7\u533a\uff1a**\\n\\n1. \u8c08\u85aa\u7ed3\u675f\u540e\u4e0d\u8981\u8f7b\u6613argue\u85aa\u8d44\uff0c\u4e0d\u7136\u5f88\u6709\u53ef\u80fd\u88ab\u53d6\u6d88\u610f\u5411\u3002\\n2. \u5bf9\u4e8e\u60f3\u53bb\u7684\u516c\u53f8\u4e0d\u8981\u968f\u4fbf\u62ff\u5176\u4ed6offer\u6765\u62ac\u4ef7\uff0c\u5bf9\u4e8e\u4e0d\u60f3\u53bb\u7684\u516c\u53f8\u53ef\u4ee5\u62ac\u9ad8\u4e00\u70b9\u3002\u5bf9\u4e8e\u6821\u62db\u5c97\u4f4d\u85aa\u8d44\u901a\u5e38\u662f\u6709\u4e0a\u9650\u7684\u3002\\n\\n### 4.5 \u4e09\u65b9\u534f\u8bae\\n\\n\u9700\u8981\u8bb0\u4f4f\u4e09\u65b9\u534f\u8bae\u4e2d\u6ca1\u6709\u4eba\u662f\u4f60\u7684\u76df\u53cb\uff0c\u5b66\u6821\u53ea\u60f3\u8981\u5c31\u4e1a\u7387\uff0cHR\u53ea\u60f3\u5feb\u70b9\u5b8c\u6210KPI\u3002\u5b66\u751f\u6bc1\u7ea6\u6210\u672c\u6781\u9ad8\uff0c\u4f01\u4e1a\u6bc1\u7ea6\u6210\u672c\u53ef\u4ee5\u5ffd\u7565\u4e0d\u8ba1\u3002\u53ea\u6709\u4f60\u81ea\u5df1\u9700\u8981\u4e3a\u81ea\u5df1\u672a\u6765\u4e00\u5230\u4e24\u5e74\u7684\u751f\u6d3b\u8d1f\u8d23\u3002\u54b1\u7ec4\u5927\u90e8\u5206\u4eba\u90fd\u662f\u572811-12\u6708\u4efd\u62ff\u5230\u5fc3\u4eea\u7684offer\uff0c\u6240\u4ee5\u5982\u679c\u662f9-10\u6708\u4efd\u9047\u5230\u4e0d\u662f\u7279\u522b\u6ee1\u610f\u7684offer\uff0c\u53ef\u4ee5\u62d2\u6389\u3002\\n\\n\u73b0\u5728\u4e09\u65b9\u57fa\u672c\u662f\u7f51\u7b7e\uff0c\u4f46\u662f\u53ef\u4ee5\u627e\u5bfc\u5458\u62ff\u7eb8\u8d28\u4e09\u65b9\uff0c\u4f01\u4e1a\u76d6\u5b8c\u7ae0\u4e0d\u4e0a\u4f20\u7cfb\u7edf\u628a\u7f51\u7edc\u4e09\u65b9\u7a7a\u51fa\u6765\u3002\u4f46\u662f\u8fd9\u662f\u94bb\u7a7a\u5b50\uff0c\u4e2a\u4eba\u4e0d\u63a8\u8350\u8fd9\u79cd\u884c\u4e3a\u3002\u8fd9\u91cc\u5217\u51fa\u6765\u53ea\u662f\u63d0\u4f9b\u4e00\u4e2a\u65b9\u6848\uff0c\u7ed9\u90a3\u4e9b\u60f3\u53bb\u53ea\u8981\u7a7a\u767d\u4e09\u65b9\u592e\u56fd\u4f01\uff0c\u4f46\u662f\u53c8\u60f3\u8981\u4e2a\u4fdd\u5e95\u7684\u4eba\u3002\\n\\n## 5 \u751f\u6d3b\u7bc7\\n\\n1. \u79df\u623f\u4e3b\u8981\u5206\u4e3a\u4e09\u79cd\u65b9\u5f0f\uff1a\u5c45\u6c11\u697c\uff08\u5408\u79df\u6216\u8005\u6574\u79df\uff0c\u81ea\u5982\uff09\u3001\u54c1\u724c\u516c\u5bd3\uff08\u6cca\u5bd3\u3001\u51a0\u5bd3\uff0c\u81ea\u5982\uff09\u3001\u653f\u7b56\u6027\u79df\u623f\uff08\u4eba\u624d\u516c\u5bd3\uff09\u3002\u6ce8\u610f\u6c34\u7535\u4ef7\u683c\u662f\u6c11\u7528\u4ef7\u683c\u8fd8\u662f\u5546\u7528\u4ef7\u683c\uff0c\u4ee5\u53ca\u5bb6\u7535\u7684\u80fd\u8017\u3002\u901a\u5e38\u8981\u4ea4\u62bc\u91d1\u6216\u8005\u5148\u4ea4\u51e0\u4e2a\u6708\u7684\u623f\u79df\uff0c\u5efa\u8bae\u5148\u51c6\u5907\u597d\u56db\u4e2a\u6708\u7684\u623f\u79df\u3002\u60f3\u7701\u94b1\u53ef\u4ee5\u5173\u6ce8\u4eba\u624d\u79df\u623f\u548c\u4fdd\u969c\u79df\u623f\u3002\\n2. \u4e94\u70b9\u4e0b\u73ed\u548c\u4e5d\u70b9\u4e0b\u73ed\u539f\u6765\u771f\u7684\u662f\u4e24\u4e2a\u57ce\u5e02\uff0c\u6240\u4ee5\u5c3d\u91cf\u5728\u901a\u52e4\u65b9\u4fbf\u7684\u5730\u65b9\u3002\\n\\n## 6 \u8d44\u6599\u7bc7\\n\\n### 6.1 \u5c97\u4f4d\u4fe1\u606f\\n\\n[26\u5c4a\u5b9e\u4e60\u6821\u62db\u5185\u63a8\u6c47\u603b\u5e16\uff08\u9644\u7b14\u9762\u7ecf\u771f\u9898\u8d44\u6599\uff09](https://docs.qq.com/doc/DYldjRG5oUENZZ0xX)\\n[26\u5c4a\u6821\u62db\u4fe1\u606f\u6c47\u603b\uff08\u6301\u7eed\u66f4\u65b0\uff09](https://docs.qq.com/sheet/DZlRLZlJETm9WQlpk?u=3cb4ec34dc31417c8b0a6225dacefcae&tab=BB08J2)\\n[OfferShow - \u5927\u5b66\u751f\u6c42\u804c\u627e\u5de5\u4f5c\u795e\u5668\uff0c\u540d\u4f01\u5185\u63a8\uff0c\u85aa\u8d44\u67e5\u8be2\uff0cOffer\u9009\u62e9\uff0c\u505a\u5927\u5b66\u751f\u503c\u5f97\u4fe1\u8d56\u7684\u4f19\u4f34_\u804c\u6653\u79d1\u6280](https://offershow.cn/)\\n\\n### 6.2 \u516b\u80a1\\n\\nJava\uff1a[\u5c0f\u6797coding | Java\u9762\u8bd5\u5b66\u4e60](https://www.xiaolincoding.com/)\\nc++:  [CS\u57fa\u7840-\u5c0f\u8d3a.pdf](https://jingtao.fun/downloads/documents/CS%E5%9F%BA%E7%A1%80-%E5%B0%8F%E8%B4%BA.pdf)\\n\u5927\u6a21\u578b\uff1a[\u6df1\u5ea6\u5b66\u4e60 \u2014 PaddleEdu documentation](https://paddlepedia.readthedocs.io/en/latest/tutorials/deep_learning/index.html)\\n\\n[wdndev/llm_interview_note: \u4e3b\u8981\u8bb0\u5f55\u5927\u8bed\u8a00\u5927\u6a21\u578b\uff08LLMs\uff09 \u7b97\u6cd5\uff08\u5e94\u7528\uff09\u5de5\u7a0b\u5e08\u76f8\u5173\u7684\u77e5\u8bc6\u53ca\u9762\u8bd5\u9898](https://github.com/wdndev/llm_interview_note)\\n\\n[\u725b\u5ba2\u7f51\u516c\u53f8\u771f\u9898_\u514d\u8d39\u9762\u8bd5\u9898\u5e93_\u4f01\u4e1a\u9762\u8bd5|\u9762\u8bd5\u771f\u9898](https://www.nowcoder.com/exam/interview?order=0)\\n\\ncuda\u516b\u80a1\uff1a[CUDATutorial | Notebook](https://cuda.keter.top/)\\n\\nAgent\uff1a[Hello-Agents](https://datawhalechina.github.io/hello-agents/#/)\\n\\n### 6.3 \u624b\u6495\\n\\n[\u5206\u4eab\uff5c\u5982\u4f55\u79d1\u5b66\u5237\u9898\uff1f - \u8ba8\u8bba - \u529b\u6263\uff08LeetCode\uff09](https://leetcode.cn/discuss/post/3141566/ru-he-ke-xue-shua-ti-by-endlesscheng-q3yd/)\\n\\n[\u672c\u7ad9\u7b80\u4ecb | labuladong \u7684\u7b97\u6cd5\u7b14\u8bb0](https://labuladong.online/algo/home/)\\n\u5927\u5382\u771f\u9898\uff1a[\u9996\u9875 - CodeFun2000](https://codefun2000.com/)\\n\\nCUDA:[LeetGPU - The GPU Programming Platform](https://leetgpu.com/)\\n\\n\u5927\u6a21\u578b\uff1a[Practice Problems | Deep-ML](https://www.deep-ml.com/problems)\\n\\n### 6.4 \u7b80\u5386\u6a21\u677f\\n\\n[\u8c48\u98a8\u4e91\u76d8](https://cloud.qifeng.xyz/zh-CN/%E6%A8%A1%E6%9D%BF%E6%96%87%E6%A1%A3/%E7%AE%80%E5%8E%86%E6%A8%A1%E6%9D%BF.docx)"},{"id":"blog_nvtx","metadata":{"permalink":"/blog/blog_nvtx","editUrl":"https://github.com/yinxiangkai/Website/tree/main/blog/CUDA/NVTX.md","source":"@site/blog/CUDA/NVTX.md","title":"NVTX","description":"\u672c\u6587\u4ecb\u7ecdNTT\u7b97\u6cd5\u7684\u6f14\u53d8\u8fc7\u7a0b\u548c\u4e3b\u6d41\u65b9\u6848\u4ee5\u53ca\u90e8\u5206\u5de5\u7a0b\u4f18\u5316\u65b9\u6cd5\u3002","date":"2026-03-05T00:00:00.000Z","tags":[{"inline":false,"label":"Cuda","permalink":"/blog/tags/cuda","description":"Cuda\u76f8\u5173\u7684\u6587\u7ae0"},{"inline":false,"label":"GPU","permalink":"/blog/tags/gpu","description":"GPU\u76f8\u5173\u7684\u6587\u7ae0"},{"inline":false,"label":"Performance Analysis","permalink":"/blog/tags/performance-analysis","description":"\u6027\u80fd\u5206\u6790\u76f8\u5173\u7684\u6587\u7ae0"}],"readingTime":2.14,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"NVTX","slug":"blog_nvtx","date":"2026-03-05T00:00:00.000Z","image":"https://image.qifeng.xyz/202507091105071.svg","hide_table_of_contents":false,"tags":["Cuda","GPU","\u6027\u80fd\u5206\u6790"]},"unlisted":false,"prevItem":{"title":"\u6c42\u804c\u8e29\u5751\u6307\u5357","permalink":"/blog/blog_job"},"nextItem":{"title":"Shared_Memory_\u5927\u5c0f\u9650\u5236","permalink":"/blog/blog_shared_memory"}},"content":"\u672c\u6587\u4ecb\u7ecdNTT\u7b97\u6cd5\u7684\u6f14\u53d8\u8fc7\u7a0b\u548c\u4e3b\u6d41\u65b9\u6848\u4ee5\u53ca\u90e8\u5206\u5de5\u7a0b\u4f18\u5316\u65b9\u6cd5\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## 1 \u4ecb\u7ecd\uff1a\\n\\nNVTX \u662f\u4e00\u79cd\u57fa\u4e8e C/C++ \u7684 API\uff0c\u7528\u4e8e\u6807\u6ce8\u7a0b\u5e8f\u4e2d\u7684\u4ee3\u7801\u8303\u56f4\u3001\u4e8b\u4ef6\u548c\u8d44\u6e90\u3002\u6b64\u6807\u6ce8\u652f\u6301\u5728\u5e94\u7528\u7a0b\u5e8f\u8fd0\u884c\u65f6\u6536\u96c6\u66f4\u591a\u4fe1\u606f\uff0c\u8fd9\u4e9b\u4fe1\u606f\u53ef\u7528\u4e8e\u5728\u5206\u6790CUDA\u4ee3\u7801\u65f6\u6539\u8fdb\u6570\u636e\u5448\u73b0\u3002\\n\\n## 2 \u4f7f\u7528\\n\\n### 2.1 \u5f15\u7528\u5934\u6587\u4ef6\\n\\n```cpp\\n#include <nvtx3/nvtx3.hpp>//C++\uff0c\u6709\u53ef\u80fd\u6ca1\u6709\u5b89\u88c5\u4e0a\uff0c\u76f4\u63a5\u7528c\u7684\u5c31\u884c\u3002\\n#include <nvtx3/nvToolsExt.h>  //C\\n```\\n\\n### 2.2 \u5e38\u7528\u529f\u80fd\\n\\n#### 2.2.1 \u8303\u56f4\u63cf\u8ff0\\n\\n**nvtx3::scoped_range\uff1a** \u7528\u4e8e\u6807\u8bb0\u8be5\u7c7b\u6240\u521b\u5efa\u5bf9\u8c61\u5b58\u5728\u7684\u65f6\u95f4\u6bb5\uff0c\u4f20\u9012\u533a\u95f4\u7684\u540d\u5b57\u8fdb\u884c\u521d\u59cb\u5316\u3002\\n\\n```cpp\\nvoid some_function() {\\n   nvtx3::scoped_range r{\\"some_function\\"};//\u5bf9\u8c61r\u7684\u5b58\u5728\u57df\u662fsome_function()\\n   for(int i = 0; i < 6; ++i) {\\n      nvtx3::scoped_range loop{\\"loop range\\"};//\u5bf9\u8c61loop\u5b58\u5728\u7684\u57df\u662ffor\u5faa\u73af\u7684\u6bcf\u4e2a\u8f6e\u6b21\u3002\\n      std::this_thread::sleep_for(std::chrono::seconds{1});\\n   }\\n}\u200b\\n```\\n\\n**nvtxRange:nvtxRang\uff1a** \u901a\u8fc7\u4f7f\u7528nvtxRangePushA( )\u548cnvtxRangePop( )\u624b\u52a8\u6807\u8bb0\u3002\\n\\n```cpp\\n void my_function(...) {\\n\\n   nvtxRangePushA(\\"my_function\\"); // \u533a\u95f4\u5f00\u59cb\u4f4d\u7f6e\\n\\n   //\\n\\n   nvtxRangePop(); // \u533a\u95f4\u7ed3\u675f\u4f4d\u7f6e\\n\\n}\\n```\\n\\n#### 2.2.2 \u6807\u8bb0\u4e8b\u4ef6\u70b9\\n\\n**nvtx3::mark:**\\n\\n```cpp\\nbool success = do_operation(...);\\nif (!success) {\\n   nvtx3::mark(\\"operation failed!\\");\\n}\\n```\\n\\n### 2.3 \u5b9e\u9645\u4f7f\u7528\\n\\n\u63d2\u6869\u540e\u4f1a\u7684\u5f71\u54cd\u4ee3\u7801\u6027\u80fd\uff0c\u56e0\u6b64\u5e94\u5f53\u53ea\u5728\u9700\u8981\u7684\u65f6\u5019\u5bf9\u76f8\u5173\u4ee3\u7801\u8fdb\u884c\u7f16\u8bd1\u3002\u53ef\u4ee5\u5b8f\u5bf9\u4ee3\u7801\u8fdb\u884c\u63a7\u5236\u3002\\n\\n```cpp\\n\\n#ifdef NVTX\\n    //\u76f8\u5173\u547d\u4ee4\\n#endif\\t\\n```\\n\\n\u7136\u540e\u518dcmake \u4e2d\u6dfb\u52a0\u76f8\u5e94\u7684\u63a7\u5236\u6307\u4ee4\\n\\n```cmake\\n\\nif(NVTX)\\n\\tadd_definitions(-DNVTX)\\nENDIF()\\n```\\n\\n\u5728\u6267\u884c\u7f16\u8bd1\u65f6\u6dfb\u52a0\u53c2\u6570\u3002\\n\\n```shell\\ncmake -D NVTX=1 ..\\nmake\\n```\\n\\n## 3 \u95ee\u9898\\n\\n\u5982\u679c\u6ca1\u6709nvtx3.hpp\uff0c\u53ef\u4ee5\u4ece[NVTX/c/include/nvtx3 at release-v3 \xb7 NVIDIA/NVTX (github.com)](https://github.com/NVIDIA/NVTX/tree/release-v3/c/include/nvtx3)\u4e2d\u4e0b\u8f7d\uff0c\u6dfb\u52a0\u5230 /usr/local/cuda-12.3/include/nvtx3 \u76ee\u5f55\u4e0b\u5373\u53ef\u3002\\n\\n## 4 \u53c2\u8003\u6587\u732e\\n\\n[1]CUDA Pro Tip: Generate Custom Application Profile Timelines with NVTX[EB/OL]//NVIDIA Technical Blog. (2013-09-04)[2024-09-11]. [https://developer.nvidia.com/blog/cuda-pro-tip-generate-custom-application-profile-timelines-nvtx/](https://developer.nvidia.com/blog/cuda-pro-tip-generate-custom-application-profile-timelines-nvtx/).\\n\\n[2]NVIDIA/NVTX[CP/OL]. NVIDIA Corporation, 2024[2024-09-11]. [https://github.com/NVIDIA/NVTX](https://github.com/NVIDIA/NVTX).\\n\\n[3]NVTX C++ API Reference: NVTX C++ API Reference[EB/OL]. [2024-09-11]. [https://nvidia.github.io/NVTX/doxygen-cpp/index.html](https://nvidia.github.io/NVTX/doxygen-cpp/index.html).\\n\\n\u200d"},{"id":"blog_shared_memory","metadata":{"permalink":"/blog/blog_shared_memory","editUrl":"https://github.com/yinxiangkai/Website/tree/main/blog/CUDA/Shared_Memory_\u5927\u5c0f\u9650\u5236.md","source":"@site/blog/CUDA/Shared_Memory_\u5927\u5c0f\u9650\u5236.md","title":"Shared_Memory_\u5927\u5c0f\u9650\u5236","description":"\u672c\u6587\u4ecb\u7ecdNTT\u7b97\u6cd5\u7684\u6f14\u53d8\u8fc7\u7a0b\u548c\u4e3b\u6d41\u65b9\u6848\u4ee5\u53ca\u90e8\u5206\u5de5\u7a0b\u4f18\u5316\u65b9\u6cd5\u3002","date":"2026-03-05T00:00:00.000Z","tags":[{"inline":false,"label":"Cuda","permalink":"/blog/tags/cuda","description":"Cuda\u76f8\u5173\u7684\u6587\u7ae0"},{"inline":false,"label":"GPU","permalink":"/blog/tags/gpu","description":"GPU\u76f8\u5173\u7684\u6587\u7ae0"},{"inline":false,"label":"Parallel Computing","permalink":"/blog/tags/parallel-computing","description":"\u5e76\u884c\u8ba1\u7b97\u76f8\u5173\u7684\u6587\u7ae0"}],"readingTime":1.405,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"Shared_Memory_\u5927\u5c0f\u9650\u5236","slug":"blog_shared_memory","date":"2026-03-05T00:00:00.000Z","image":"https://image.qifeng.xyz/202507091105071.svg","hide_table_of_contents":false,"tags":["Cuda","GPU","\u5e76\u884c\u8ba1\u7b97"]},"unlisted":false,"prevItem":{"title":"NVTX","permalink":"/blog/blog_nvtx"},"nextItem":{"title":"\u8ba4\u8bc6GPU","permalink":"/blog/blog_GPU"}},"content":"\u672c\u6587\u4ecb\u7ecdNTT\u7b97\u6cd5\u7684\u6f14\u53d8\u8fc7\u7a0b\u548c\u4e3b\u6d41\u65b9\u6848\u4ee5\u53ca\u90e8\u5206\u5de5\u7a0b\u4f18\u5316\u65b9\u6cd5\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## 1 \u95ee\u9898\u63cf\u8ff0\\n\\ncuda\u4ee3\u7801\u6709\u65f6\u4f1a\u62a5\u5982\u4e0b\u7684\u9519\u8bef\uff0c\u5373\u975e\u6cd5\u53d8\u91cf\uff0c\u8fd9\u662f\u56e0\u4e3a\u5916\u90e8\u8bbe\u7f6e\u5171\u4eab\u5185\u5b58\u7684\u5927\u5c0f\u662f\u6709\u9650\u5236\u7684\u3002\\n\\n```shell\\nError code:1\\nError text:invalid argument\\n```\\n\\n\u56e0\u4e3a\u6838\u51fd\u6570\u5bf9\u5171\u4eab\u5185\u5b58\u7684\u9700\u6c42\u662f\u4e0d\u5b9a\u7684\u4e3a\u4e86\u66f4\u597d\u7684\u5229\u7528\u8d44\u6e90\u4ee5\u53ca\u5e2e\u52a9\u7f16\u8bd1\u5668\u8fdb\u884c\u4f18\u5316\uff0c\u901a\u5e38\u4f1a\u91c7\u53d6\u4f20\u9012\u5171\u4eab\u5185\u5b58\u5927\u5c0f\u7684\u65b9\u5f0f\u3002\\n\\n```shell\\nkernelFunc<<<gridDim\uff0cblockDim\uff0csharedmem>>>()\\n```\\n\\n\u5171\u4eab\u5185\u5b58\u548c\u4e00\u7ea7\u7f13\u5b58\u5171\u7528\u540c\u4e00\u786c\u4ef6\u5b58\u50a8\u5355\u5143\u3002\u56e0\u6b64\u5171\u4eab\u5185\u5b58\u6709\u6700\u9ad8\u4e0a\u9650\uff0c\u4e14\u8be5\u4e0a\u9650\u4e0d\u7b49\u540c\u4e8e\u786c\u4ef6\u4e0a\u9650\u3002\u4f8b\u5982H100 L1\u548c\u5171\u4eab\u5185\u5b58\u5927\u5c0f\u4e4b\u548c\u4e3a256KB\uff0c\u800c\u5355\u4e2aSM\u5171\u4eab\u5185\u5b58\u6700\u591a\u4f7f\u7528228KB\uff0c\u800c\u6bcf\u4e2ablock\u6700\u591a\u4f7f\u7528227KB\uff0c\u4f46\u662f\u51fa\u4e8e\u8d44\u6e90\u8c03\u5ea6\u7b49\u8003\u8651\u4f1a\u9ed8\u8ba4\u9650\u5236\u4e3a48KB\u3002\\n\\n## 2 \u89e3\u51b3\\n\\n\u53ef\u4ee5\u4f7f\u7528\u4e0b\u9762\u7684\u51fd\u6570\u8fdb\u884c\u8bbe\u7f6e\u3002\u76ee\u524d\u53ea\u6709\u51fd\u6570\u7ea7\u7684\u8bbe\u7f6e\uff0c\u5168\u5c40\u7ea7\u6ca1\u6709\u76f8\u5173\u7684\u8bbe\u7f6e\u3002\\n\\n```shell\\ncudaFuncSetAttribute( KernelFunc,  cudaFuncAttributeMaxDynamicSharedMemorySize, 128 \\\\* 1024 // 128 KB);\\n```\\n\\n\u200d"},{"id":"blog_GPU","metadata":{"permalink":"/blog/blog_GPU","editUrl":"https://github.com/yinxiangkai/Website/tree/main/blog/CUDA/\u8ba4\u8bc6GPU.md","source":"@site/blog/CUDA/\u8ba4\u8bc6GPU.md","title":"\u8ba4\u8bc6GPU","description":"\u672c\u6587\u4ecb\u7ecdNTT\u7b97\u6cd5\u7684\u6f14\u53d8\u8fc7\u7a0b\u548c\u4e3b\u6d41\u65b9\u6848\u4ee5\u53ca\u90e8\u5206\u5de5\u7a0b\u4f18\u5316\u65b9\u6cd5\u3002","date":"2026-03-05T00:00:00.000Z","tags":[{"inline":false,"label":"Cuda","permalink":"/blog/tags/cuda","description":"Cuda\u76f8\u5173\u7684\u6587\u7ae0"},{"inline":false,"label":"GPU","permalink":"/blog/tags/gpu","description":"GPU\u76f8\u5173\u7684\u6587\u7ae0"},{"inline":false,"label":"Parallel Computing","permalink":"/blog/tags/parallel-computing","description":"\u5e76\u884c\u8ba1\u7b97\u76f8\u5173\u7684\u6587\u7ae0"}],"readingTime":24.62,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"\u8ba4\u8bc6GPU","slug":"blog_GPU","date":"2026-03-05T00:00:00.000Z","image":"https://image.qifeng.xyz/202507091105071.svg","hide_table_of_contents":false,"tags":["Cuda","GPU","\u5e76\u884c\u8ba1\u7b97"]},"unlisted":false,"prevItem":{"title":"Shared_Memory_\u5927\u5c0f\u9650\u5236","permalink":"/blog/blog_shared_memory"}},"content":"\u672c\u6587\u4ecb\u7ecdNTT\u7b97\u6cd5\u7684\u6f14\u53d8\u8fc7\u7a0b\u548c\u4e3b\u6d41\u65b9\u6848\u4ee5\u53ca\u90e8\u5206\u5de5\u7a0b\u4f18\u5316\u65b9\u6cd5\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## 1 GPU\u7b80\u5355\u4ecb\u7ecd\\n\\nGPU(Graphics Processing Unit)\u4e5f\u53eb\u505a\u56fe\u5f62\u5904\u7406\u5355\u5143\uff0c\u662f\u4e00\u79cd\u4e13\u7528\u7535\u5b50\u7535\u8def\uff0c\u6700\u521d\u8bbe\u8ba1\u4f7f\u7528\u6765\u52a0\u901f\u8ba1\u7b97\u673a\u56fe\u5f62\u5904\u7406\uff0c\u4f46\u540e\u7eed\u56e0\u5176\u5e76\u884c\u7ed3\u6784\u975e\u5e38\u9002\u5408\u4e0e\u5e76\u884c\u8ba1\u7b97\u9886\u57df\u3002GPU\u4e00\u5171\u7ecf\u5386\u4e86\u4e09\u4e2a\u5386\u53f2\u53d1\u5c55\u9636\u6bb5\u3002\u4e0b\u9762\u662f\u663e\u5361\u793a\u610f\u56fe\uff0c\u4e3b\u8981\u7531GPU\u548c\u663e\u5b58\u7ec4\u6210\u3002![GPU\u793a\u610f\u56fe](https://image.qifeng.xyz/202403061543299.png \\"GPU\u793a\u610f\u56fe\\")\\n\\n### 1.1 GPU\u7684\u53d1\u5c55\u9636\u6bb5\\n\\n#### 1.1.1 \u786c\u4ef6\u52a0\u901f\u9636\u6bb5\\n\\n\u57281999\u5e74\u4ee5\u524d\uff0c\u5c06CPU\u7684\u90e8\u5206\u529f\u80fd\u5265\u79bb\u51fa\u6765\uff0c\u5f62\u6210\u5355\u72ec\u7684\u786c\u4ef6\uff0c\u5b9e\u73b0\u5bf9\u56fe\u50cf\u7684\u786c\u4ef6\u52a0\u901f\uff0c\u53ea\u8d77\u52303D\u56fe\u50cf\u5904\u7406\u7684\u52a0\u901f\u4f5c\u7528\uff0c\u4e0d\u5177\u5907\u8f6f\u4ef6\u7f16\u7a0b\u7279\u5f81\u3002\\n\\n#### 1.1.2 \u6709\u9650\u7f16\u7a0b\u9636\u6bb5\\n\\n1999-2005\u5e74\uff0c\u8fdb\u4e00\u6b65\u7684\u786c\u4ef6\u52a0\u901f\uff0c\u4f46\u662f\u51fa\u73b0\u4e86\u6709\u9650\u7f16\u7a0b\u6027\u3002\\n\\n1999\u5e74\uff0cNvidia\u53d1\u5e03\u4e86\u4e13\u4e3a\u6267\u884c\u590d\u6742\u7684\u6570\u5b66\u548c\u51e0\u4f55\u8ba1\u7b97\u7684GeForce256\u56fe\u50cf\u5904\u7406\u82af\u7247\uff0c\u4e0d\u540c\u4e8eCPU\u5c06\u6676\u4f53\u7ba1\u4e3b\u8981\u7528\u4f5c\u63a7\u5236\u5355\u5143\u548c\u7f13\u5b58\uff0c\u66f4\u591a\u7684\u4f5c\u4e3a\u6267\u884c\u5355\u5143,\u5c06\u56fe\u5f62\u53d8\u6362\u4ee5\u53ca\u7167\u660e\u7b49\u529f\u80fd\u4eceCPU\u5265\u79bb\u51fa\u6765\uff0c\u901a\u8fc7\u53d8\u6362\u5f15\u64ce\u548c\u7167\u660e\u5f15\u64ce\u5b9e\u73b0\u4e86\u56fe\u5f62\u7684\u5feb\u901f\u53d8\u6362\u4ee5\u53ca\u5149\u7167\u8ba1\u7b97\uff0c\u6210\u4e3aGPU\u51fa\u73b0\u7684\u6807\u5fd7\u3002\\n\\n2000-2005\uff0cGPU\u6280\u672f\u5feb\u901f\u53d1\u5c55\uff0c\u8fd0\u7b97\u901f\u5ea6\u8fc5\u901f\u8d85\u8fc7GPU\u3002Nvidia\u548cATI\uff08\u88abAMD\u6536\u8d2d\uff09\u5206\u522b\u63a8\u51fa\u7684GeForce3\u548cRadeon 8500 ,\u51fa\u73b0\u9876\u70b9\u53ef\u7f16\u7a0b\u6027\u548c\u50cf\u7d20\u7ea7\u53ef\u7f16\u7a0b\u6027\uff0c\u4f46\u662f\u603b\u4f53\u4e0a\u7f16\u7a0b\u6027\u5341\u5206\u6709\u9650\u3002\\n\\n#### 1.1.3 \u8f6f\u4ef6\u53ef\u7f16\u7a0b\u9636\u6bb5\\n\\n2006\u5e74\uff0cNvidia\u548cATI\u5206\u522b\u63a8\u51fa\u4e86CUDA\uff08Compute United Device Architecture)\u548cCTM\uff08Close To Metal)\u7f16\u7a0b\u73af\u5883\uff0c\u4f7f\u5f97GPU\u6253\u7834\u56fe\u5f62\u8bed\u8a00\u7684\u5c40\u9650\u6210\u4e3a\u771f\u6b63\u7684\u989d\u5e76\u884c\u6570\u636e\u5904\u7406\u8d85\u7ea7\u52a0\u901f\u5668\u3002\\n\\n2008\u5e74\uff0c\u82f9\u679c\u63d0\u51fa\u901a\u7528\u7684\u5e76\u884c\u8ba1\u7b97\u7f16\u7a0b\u5e73\u53f0OpenCL,\u4e0e\u5177\u4f53\u5e73\u53f0\u65e0\u5173\uff0c\u8fc5\u901f\u6210\u4e3a\u79fb\u52a8\u7aefGPU\u7684\u7f16\u7a0b\u73af\u5883\u4e1a\u754c\u6807\u51c6\u3002![Nvidia\u8f6f\u4ef6\u751f\u6001.png](https://image.qifeng.xyz/202403061544076.webp )\\n\\n### 1.2 GPU\u5de5\u4f5c\u539f\u7406\\n\\n#### 1.2.1 1.2.1\u57fa\u672c\u6982\u5ff5\u89e3\u91ca\\n\\nGPU\u7684\u8bbe\u8ba1\u76ee\u6807\u662f\u6700\u5927\u5316\u541e\u5410\u91cf\uff08Throughout\uff09\u548c\u5e76\u884c\u5ea6\uff08Parallelism\uff09\u3002\u800cCPU\u66f4\u5173\u5fc3\u5ef6\u8fdf\uff08Latency\uff09\u548c\u5e76\u53d1\uff08concurrency\uff09\u3002\u4e8e\u662fGPU\u91c7\u7528\u4e86SIMT\u67b6\u6784\uff0c\u5355\u6838CPU\u901a\u5e38\u91c7\u7528SIMD\u67b6\u6784\uff0c\u591a\u6838CPU\u5219\u901a\u5e38\u91c7\u7528MIMD\u67b6\u6784\u3002\\n\\nCPU\u65e8\u5728\u4ee5\u5c3d\u53ef\u80fd\u5feb\u7684\u901f\u5ea6\u6267\u884c\u7ebf\u7a0b\uff0c\u5e76\u4e14\u53ef\u4ee5\u5e76\u884c\u6267\u884c\u51e0\u5341\u4e2a\u8fd9\u4e9b\u7ebf\u7a0b\u3002\u800cGPU\u8bd5\u56fe\u901a\u8fc7\u5e76\u884c\u6267\u884c\u6570\u5343\u4e2a\u7ebf\u7a0b\u4ece\u800c\u5206\u644a\u65f6\u5ef6\u4ee5\u5b9e\u73b0\u66f4\u9ad8\u7684\u541e\u5410\u91cf\u3002 GPU\u4e13\u95e8\u7528\u4e8e\u9ad8\u5ea6\u5e76\u884c\u8ba1\u7b97\uff0c\u56e0\u6b64\u8bbe\u8ba1\u65f6\u66f4\u591a\u7684\u6676\u4f53\u7ba1\u7528\u4e8e\u6570\u636e\u5904\u7406\u800c\u4e0d\u662f\u6570\u636e\u7f13\u5b58\u548c\u6d41\u7a0b\u63a7\u5236\u3002\\n\\n![CPU \u4e0e GPU](https://image.qifeng.xyz/202404101935078.svg \\"CPU \u4e0e GPU\\")\u200b\\n\\n**\u541e\u5410\u91cf\uff1a** \u5355\u4f4d\u65f6\u95f4\u5185\u80fd\u591f\u5b8c\u6210\u7684\u64cd\u4f5c\u3002\\n\\n**\u5ef6\u8fdf\uff1a** \u5b8c\u6210\u5355\u9879\u4efb\u52a1\u6240\u6d88\u8017\u7684\u65f6\u95f4\u3002\\n\\n**\u5e76\u884c\uff1a** \u540c\u65f6\u5904\u7406\u591a\u4e2a\u4efb\u52a1\uff0c\u4efb\u52a1\u4e4b\u95f4\u5b58\u5728\u5e72\u6270\u3002\\n\\n**\u5e76\u53d1\uff1a** \u4e00\u6bb5\u65f6\u95f4\u5185\u5904\u7406\u591a\u4e2a\u4efb\u52a1\uff0c\u4efb\u52a1\u4e4b\u95f4\u53ef\u80fd\u4e92\u76f8\u5e72\u6270\u3002\\n\\n**SIMD\uff1a** SIMD(\u5355\u6307\u4ee4\u591a\u6570\u636e\u6d41)\u662f\u4eceSISD\uff08\u5355\u6307\u4ee4\u5355\u6570\u636e\u6d41\uff09\u53d1\u5c55\u51fa\u6765\u7684\u3002\u60f3\u8981\u6267\u884c\u5e76\u884c\u9700\u8981\u901a\u8fc7\u5806\u53e0\u591a\u4e2a\u6838\u5fc3\u4ece\u800c\u5b9e\u73b0\u5e76\u884c\uff0c\u6bcf\u4e2a\u6838\u5fc3\u6267\u884c\u4e00\u4e2a\u7ebf\u7a0b\uff0c\u5373MIMD\uff08\u591a\u6307\u4ee4\u591a\u6570\u636e\u6d41\uff09\u3002\u800cSIMD\u7684\u60f3\u6cd5\u662f\u901a\u8fc7\u7ed9\u6bcf\u4e2a\u6838\u5fc3\u4e2d\u589e\u52a0\u8ba1\u7b97\u5355\u5143\u548c\u5bc4\u5b58\u5668\uff0c\u51cf\u5c11\u786c\u4ef6\u5f00\u9500\u3002\u7136\u540e\u589e\u52a0\u6307\u4ee4\u7684\u64cd\u4f5c\u6570\u4e2a\u6570\uff0c\u4f7f\u5f97\u4e00\u6761\u6307\u4ee4\u53ef\u4ee5\u9a71\u52a8\u591a\u4e2a\u8ba1\u7b97\u5143\u4ef6\u540c\u65f6\u6267\u884c\u591a\u4e2a\u6570\u636e\u8fd0\u7b97\u3002\\n\\n**SIMT\uff1a** SIMD\u770b\u8d77\u6765\u5f88\u597d\uff0c\u4f46\u662f\u5bf9\u4e8e\u9ad8\u7ea7\u8bed\u8a00\u7684\u652f\u6301\u5e76\u4e0d\u597d\u3002SIMT\uff08\u5355\u6307\u4ee4\u591a\u7ebf\u7a0b\uff09\u4ece\u672c\u8d28\u4e0a\u8fd8\u662f\u4e00\u5957\u63a7\u5236\u5355\u5143\u5e26\u591a\u4e2a\u8ba1\u7b97\u5355\u5143\uff0c\u4f46\u662f\u4ece\u4e00\u6761\u6307\u4ee4\u63a7\u5236\u591a\u4e2a\u8ba1\u7b97\u5355\u5143\u548c\u5bc4\u5b58\u5668\uff0c\u53d8\u4e3a\u5c06\u4e00\u6761\u6307\u4ee4\u5206\u53d1\u7ed9\u591a\u7ec4\u8ba1\u7b97\u5355\u5143\u548c\u5bc4\u5b58\u5668\uff0c\u4ece\u800c\u4f18\u5316\u9ad8\u7ea7\u8bed\u8a00\u7684\u652f\u6301\u3002\\n\\n#### 1.2.2 \u7f13\u5b58\u673a\u5236\\n\\nCPU\u4e2d\u7684\u7f13\u5b58\u662f\u4e3a\u4e86\u5b58\u50a8\u4e0b\u4e00\u6b65\u8981\u8ba1\u7b97\u7684\u6570\u636e\uff0c\u4ece\u800c\u51cf\u5c11\u8bbf\u95ee\u6570\u636e\u7684\u65f6\u5ef6\uff0c\u63d0\u9ad8\u7ebf\u7a0b\u7684\u6267\u884c\u901f\u5ea6\uff0c\u4ece\u800c\u5b9e\u73b0\u9ad8\u5e76\u53d1\u3002\u800c\u5728GPU\u4e2d\u7f13\u5b58\u662f\u4e3aThread\u63d0\u4f9b\u670d\u52a1\u7684\uff0c\u7f13\u5b58\u4f1a\u5408\u5e76\u7ebf\u7a0b\u76f8\u540c\u7684\u6570\u636e\u8bbf\u95ee\uff0c\u8ba9\u540e\u4eceDRAM\u4e2d\u8bbf\u95ee\u6570\u636e\uff0c\u5206\u53d1\u7ed9\u7ebf\u7a0b\u3002\\n\\n![A100 \u5185\u5b58\u793a\u610f\u56fe](https://image.qifeng.xyz/202403061544897.svg \\"A100 \u5185\u5b58\u793a\u610f\u56fe\\")\u200b\\n\\n**SM(Streaming Multiprocessor)**  \uff1aSM\u662f\u662fGPU\u7684\u4e3b\u8981\u8ba1\u7b97\u5355\u5143\uff0c\u8d1f\u8d23\u6267\u884c\u5e76\u884c\u8ba1\u7b97\u4efb\u52a1\u3002\u6bcf\u4e2aSM\u90fd\u5305\u542b\u591a\u4e2a\u6d41\u591a\u5904\u7406\u5668\uff08CUDA\u6838\u5fc3\uff09\uff0c\u53ef\u4ee5\u540c\u65f6\u6267\u884c\u591a\u4e2a\u7ebf\u7a0b\u5757\u4e2d\u7684\u6307\u4ee4\u3002SM\u901a\u8fc7\u5206\u914d\u7ebf\u7a0b\u3001\u8c03\u5ea6\u6307\u4ee4\u548c\u7ba1\u7406\u5185\u5b58\u7b49\u64cd\u4f5c\uff0c\u5b9e\u73b0\u9ad8\u6548\u7684\u5e76\u884c\u8ba1\u7b97\u3002\\n\\n**HBM\uff1a** \u9ad8\u5e26\u5bbd\u5185\u5b58\uff0c\u4e5f\u5c31\u662f\u663e\u5b58\u3002\u5b83\u901a\u8fc7\u5c06\u5185\u5b58\u82af\u7247\u76f4\u63a5\u5806\u53e0\u5728\u903b\u8f91\u82af\u7247\u4e0a\uff0c\u63d0\u4f9b\u4e86\u6781\u9ad8\u7684\u5e26\u5bbd\u548c\u66f4\u4f4e\u7684\u80fd\u8017\uff0c\u4ece\u800c\u5b9e\u73b0\u4e86\u9ad8\u5bc6\u5ea6\u548c\u9ad8\u5e26\u5bbd\u7684\u6570\u636e\u4f20\u8f93\u3002\\n\\n**L1 Cache/SMEM**\uff1aL1 Cache\u5305\u542b\u6307\u4ee4\u7f13\u5b58(Instruction Cache)\u548c\u6570\u636e\u7f13\u5b58\uff08Data Cache\uff09\uff0c\u5728SM\u5185\u90e8\u5b58\u50a8\u6700\u5e38\u7528\u7684\u6307\u4ee4\u548c\u6570\u636e\uff0c\u6bcf\u4e2aSM\u72ec\u4eab\u4e00\u4e2aL1 Cache\uff0c\u63d0\u4f9b\u4f4e\u5ef6\u8fdf\u548c\u9ad8\u5e26\u5bbd\u7684\u8bbf\u95ee\u3002\\n\\n**Register File**: \u7528\u4e8e\u5b58\u50a8\u4e34\u65f6\u6570\u636e\u3001\u8ba1\u7b97\u4e2d\u95f4\u7ed3\u679c\u548c\u53d8\u91cf\u3002\u79bb\u8ba1\u7b97\u5355\u5143\u6700\u8fd1\uff0c\u8bbf\u95ee\u901f\u5ea6\u975e\u5e38\u5feb\u3002\\n\\n**\u5e26\u5bbd\uff08BandWidth\uff09\uff1a** \u5355\u4f4d\u65f6\u95f4\u5185\u4f20\u8f93\u7684\u6570\u636e\u91cf\uff0c\u4e3b\u8981\u6709\u5185\u5b58\u9891\u7387\uff08Memory Data Rate\uff09\u4ee5\u53ca\u4f4d\u5bbd\uff08Memory Interface\uff09\u51b3\u5b9a\u7684\u3002\u4f8b\u5982A100\u7684\u4f4d\u5bbd\u662f5210bit\uff0c\u9891\u7387\u662f1215MHz,\u6240\u4ee5\u5e26\u5bbd\u4e3a$\\\\frac{(\\\\frac{5210}{8}\\\\times1215\\\\times10^6\\\\times2)}{10^{9}}=1555GB/s$,\u4e582\u662f\u56e0\u4e3aDDR\u6280\u672f\u6bcf\u4e2a\u65f6\u949f\u5468\u671f\u4f20\u8f93\u4e24\u6b21\u6570\u636e\uff0c\u8ba1\u7b97\u5b58\u50a8\u548c\u4f20\u8f93\u65f6\u8fdb\u5236\u662f$10^3$\u3002\\n\\n**\u8ba1\u7b97\u5f3a\u5ea6\uff1a** \u8ba1\u7b97\u65f6\u95f4/\u5185\u5b58\u8bfb\u53d6\u65f6\u95f4\u3002\u5b58\u50a8\u5e26\u5bbd\u8d8a\u5c0f\u8ba1\u7b97\u5f3a\u5ea6\u5e94\u8be5\u8d8a\u9ad8\uff0c\u4ece\u800c\u63d0\u9ad8\u6548\u7387\u3002\\n\\n#### 1.2.3 \u7ebf\u7a0b\u673a\u5236\uff1a\\n\\n**Warp\uff1a**  \u7ebf\u7a0b\u675f\u3002\u903b\u8f91\u4e0a\uff0c\u6240\u6709Thread\u662f\u5e76\u884c\uff1b\u4f46\u662f\uff0c\u4ece\u786c\u4ef6\u7684\u89d2\u5ea6\u6765\u8bf4\uff0c\u5e76\u4e0d\u662f\u6240\u6709\u7684 Thread\u80fd\u591f\u5728\u540c\u4e00\u65f6\u523b\u6267\u884c\uff0c\u8fd9\u91cc\u5c31\u9700\u8981Warp\u7684\u5f15\u5165\u3002\\n\\nWarp \u662f SM \u57fa\u672c\u6267\u884c\u5355\u5143\uff0c\u4e00\u4e2a Warp \u5305\u542b32\u4e2a\u5e76\u884c Thread\uff0c\u8fd932\u4e2a Thread \u6267\u884c\u4e8e SIMT\u6a21\u5f0f\u3002\u4e5f\u5c31\u662f\u8bf4\u6240\u6709 Thread \u4ee5\u9501\u6b65\u7684\u65b9\u5f0f\u6267\u884c\u540c\u4e00\u6761\u6307\u4ee4\uff0c\u4f46\u6bcf\u4e2a Thread \u4f1a\u4f7f\u7528\u5404\u81ea\u7684 Data \u6267\u884c\u6307\u4ee4\u5206\u652f\u3002\u5982\u679c\u5728 Warp \u4e2d\u6ca1\u670932\u4e2a Thread \u9700\u8981\u5de5\u4f5c\uff0c\u90a3\u4e48 Warp \u867d\u7136\u8fd8\u662f\u4f5c\u4e3a\u4e00\u4e2a\u6574\u4f53\u8fd0\u884c\uff0c\u4f46\u8fd9\u90e8\u5206 Thread \u662f\u5904\u4e8e\u975e\u6fc0\u6d3b\u72b6\u6001\u7684\\n\\n## 2 Nvidia GPU \u4ecb\u7ecd\\n\\n### 2.1 \u57fa\u7840\u6982\u5ff5\\n\\n#### 2.1.1 CUDA\u7ebf\u7a0b\u5c42\u6b21\u7ed3\u6784\\n\\n\u5728A100\u7684\u7ebf\u7a0b\u5c42\u6b21\u4e2d\u7531\u4e09\u5c42\u6784\u6210\uff0cgrid\uff08\u7f51\u683c\uff09\u3001block\uff08\u7ebf\u7a0b\u5757\uff09\u3001thread\uff08\u7ebf\u7a0b\uff09\u3002\u4f46\u662f\u5728H100\u4e2d\u6709\u5f15\u5165\u4e86\u65b0\u7684\u4e00\u5c42Cluster\uff08\u7c07\uff09\u8fd9\u91cc\u6682\u4e14\u4e0d\u7ba1\u3002\\n\\n\u8fd9\u91cc\u59d1\u4e14\u5c06\u5728GPU\u4e0a\u7684\u4efb\u52a1\u79f0\u4e3akernel\uff0c\u4e00\u4e2akernel\u6240\u8c03\u7528\u7684\u6240\u6709\u7ebf\u7a0b\u7ec4\u6210\u4e86grid\u3002\u7f51\u683c\u53c8\u53ef\u4ee5\u62c6\u5206\u6210\u62e5\u6709\u76f8\u540c\u7ebf\u7a0b\u6570\u7684block\u3002\\n\\n**Grid\uff1a** \u540c\u4e00\u4e2a\u7f51\u683c\u4e0a\u7684\u7ebf\u7a0b\u5171\u4eab\u76f8\u540c\u7684\u5168\u5c40\u5185\u5b58\u7a7a\u95f4\u3002grid\u662f\u7ebf\u7a0b\u7ed3\u6784\u7684\u7b2c\u4e00\u5c42\u6b21\u3002\u5bf9\u5e94\u4e8eGPU\u8bbe\u5907device\u3002\\n\\n**Block\uff1a** Block \u95f4\u5e76\u884c\u6267\u884c\uff0c\u5e76\u4e14\u65e0\u6cd5\u901a\u4fe1\uff0c==\u6ca1\u6709\u6267\u884c\u987a\u5e8f==\uff0c\u6bcf\u4e2a block \u5305\u542b\u5171\u4eab\u5185\u5b58\uff08Shared Memory\uff09\uff0c\u53ef\u4ee5\u91cc\u9762\u7684 Thread \u5171\u4eab\u3002\u5bf9\u5e94\u7531\u4e8eSM\uff0cA100\u4e2d\u4e00\u4e2ablock\u5305\u542b2048\u4e2athread\u3002\\n\\n**Thread\uff1a** \u540c\u4e00\u4e2a block \u4e2d thread \u53ef\u4ee5\u540c\u6b65\uff0c\u4e5f\u53ef\u4ee5\u901a\u8fc7 Shared memory \u901a\u4fe1,\u5bf9\u5e94\u4e8ecuda core\u3002\\n\\n![Grid-Block-Thread](https://image.qifeng.xyz/202403061544578.png \\"Grid-Block-Thread\\")\\n\\n#### 2.1.2 CUDA \u5185\u5b58\u5c42\u6b21\u7ed3\u6784\\n\\n![CUDA \u5185\u5b58\u5c42\u6b21](https://image.qifeng.xyz/202403061544289.svg \\"CUDA \u5185\u5b58\u5c42\u6b21\\")\\n\\n![\u5b58\u50a8\u7ed3\u6784\u793a\u610f](https://image.qifeng.xyz/202403061544343.svg \\"\u5b58\u50a8\u7ed3\u6784\u793a\u610f\\")\\n\\n**\u5bc4\u5b58\u5668(Register)\uff1a** \u5bc4\u5b58\u5668\u5bf9\u4e8e\u6bcf\u4e2a\u7ebf\u7a0b\u6765\u8bf4\u90fd\u662f\u79c1\u6709\u7684\uff0c\u4e00\u4e2a\u6838\u51fd\u6570\u901a\u5e38\u4f7f\u7528\u5bc4\u5b58\u5668\u6765\u4fdd\u5b58\u9700\u8981\u9891\u7e41\u8bbf\u95ee\u7684\u7ebf\u7a0b\u79c1\u6709\u53d8\u91cf\u3002\u5bc4\u5b58\u5668\u53d8\u91cf\u4e0e\u6838\u51fd\u6570\u7684\u751f\u547d\u5468\u671f\u76f8\u540c\u3002\u4e00\u65e6\u6838\u51fd\u6570\u6267\u884c\u5b8c\u6bd5\uff0c\u5c31\u4e0d\u80fd\u5bf9\u5bc4\u5b58\u5668\u53d8\u91cf\u8fdb\u884c\u8bbf\u95ee\u4e86\u3002\\n\\n**\u5c40\u90e8\u5185\u5b58(Local Memory)\uff1a** \u5c40\u90e8\u5185\u5b58\u662f\u79c1\u6709\u7684\uff0c\u53ea\u6709\u672c\u7ebf\u7a0b\u624d\u80fd\u8fdb\u884c\u8bfb\u5199\u8bbf\u95ee\u3002\u4e3b\u8981\u5b58\u50a8\u8d85\u51fa\u5bc4\u5b58\u5668\u5b58\u50a8\u4e0a\u7ebf\u7684\u6570\u636e\uff0c\u4ee5\u53ca\u7f16\u8bd1\u5668\u65e0\u6cd5\u9759\u6001\u786e\u5b9a\u7684\u6570\u636e\uff0c\u5c40\u90e8\u5185\u5b58\u5728HBM\u4e0a\u3002\\n\\n**\u5171\u4eab\u5185\u5b58(Shared Memory)\uff1a** \u4e00\u4e2a\u5757\u53ef\u4ee5\u88ab\u540c\u4e00block\u4e2d\u7684\u6240\u6709\u7ebf\u7a0b\u8bbf\u95ee\u7684\u53ef\u8bfb\u5199\u5b58\u50a8\u5668\u3002\u8bbf\u95ee\u5171\u4eab\u5b58\u50a8\u5668\u7684\u901f\u5ea6\u51e0\u4e4e\u548c\u8bbf\u95ee\u5bc4\u5b58\u5668\u4e00\u6837\u5feb\u3002\u662f\u5b9e\u73b0\u7ebf\u7a0b\u95f4\u901a\u4fe1\u7684\u5ef6\u8fdf\u6700\u5c0f\u7684\u65b9\u6cd5\u3002\\n\\n**\u5e38\u91cf\u5185\u5b58(Constant Memory)\uff1a** \u5e38\u91cf\u5185\u5b58\uff08const memory\uff09\u662f\u53ea\u8bfb\u5168\u5c40\u5185\u5b58\uff0c\u5728HBM\u4e2d\uff0c\u4f46\u662f\u5176\u4e2d\u7684\u6570\u636e\u53ef\u4ee5\u7f13\u5b58\u5728SM\u5185\u90e8\u7684\u5e38\u91cf\u7f13\u5b58\u4e2d\uff08const cache\uff09\u53ea\u3002\\n\\n**\u7eb9\u7406\u5185\u5b58(Texture Memory)\uff1a** \u7eb9\u7406\u5185\u5b58\u7c7b\u4f3c\u4e8e\u5e38\u91cf\u7f13\u5b58\uff0c\u4e5f\u662f\u4e00\u79cd\u5177\u6709\u7f13\u5b58\u7684\u53ea\u8bfb\u5168\u5c40\u5185\u5b58\uff0c\u4e0e\u5e38\u91cf\u5185\u5b58\u5177\u6709\u76f8\u540c\u7684\u751f\u547d\u5468\u671f\u548c\u4f5c\u7528\u8303\u56f4\u3002\u7eb9\u7406\u5185\u5b58\u901a\u5e38\u6bd4\u5e38\u91cf\u5185\u5b58\u8981\u5927\uff0c\u9002\u5408\u5b9e\u73b0\u56fe\u50cf\u5904\u7406\u548c\u67e5\u627e\u8868\u7b49\u64cd\u4f5c\u3002\\n\\n**\u5168\u5c40\u5185\u5b58(Global Memory)\uff1a** \u5168\u5c40\u5185\u5b58\u7531\u4e8e\u5b58\u653e\u5728HBM\u4e0a\uff0c\u662fGPU\u4e2d\u5bb9\u91cf\u6700\u5927\u3001\u5ef6\u8fdf\u6700\u9ad8\u7684\u5185\u5b58\uff0c\u4e3b\u8981\u4f5c\u7528\u662f\u7ed9\u6838\u51fd\u6570\u63d0\u4f9b\u6570\u636e\u3002GPU\u5185\u6838\u7684\u6240\u6709\u7ebf\u7a0b\u90fd\u80fd\u5bf9\u5168\u5c40\u5185\u5b58\u8fdb\u884c\u8bbf\u95ee\uff0c\u4f46\u662f\u8bbf\u5b58\u7684\u5f00\u9500\u5f88\u5927\u3002\\n\\n#### 2.1.3 \u8ba1\u7b97\u6027\u80fd\\n\\n$$\\n\ud835\udc43\ud835\udc52\ud835\udc4e\ud835\udc58 \\\\ \ud835\udc39\ud835\udc3f\ud835\udc42\ud835\udc43\ud835\udc46=\ud835\udc39_{\ud835\udc50\ud835\udc59\ud835\udc58}\u2217\ud835\udc41_{\ud835\udc46\ud835\udc40}\u2217\ud835\udc39_{\ud835\udc5f\ud835\udc52\ud835\udc5e}\\n$$\\n\\n$F_{clk}$\uff1a\u4e3a GPU \u65f6\u949f\u5468\u671f\u5185\u6307\u4ee4\u6267\u884c\u6570 (FLOPS/Cycle)\u3002\\n\\n$N_{SM}$\uff1a\u4e3a GPU SM \u6570\u91cf (Cores)\u3002\\n\\n$F_{req}$\uff1a\u4e3a\u8fd0\u884c\u9891\u7387 (GHz)\u3002\\n\\n### 2.2 Nvidia\u67b6\u6784\\n\\n![\u56fe\u72471](https://image.qifeng.xyz/202403061544095.svg)\u200b\\n\\n\u6ce8\u610f\u540c\u540c\u4e00\u67b6\u6784\u4e0d\u540c\u578b\u53f7\u7684GPU\u5b58\u5728\u5dee\u5f02\u3002\\n\\n#### 2.2.1 Fermi \u8d39\u7c73\u67b6\u6784\\n\\n![Fermi \u67b6\u6784](https://image.qifeng.xyz/202403061544844.png \\"Fermi \u67b6\u6784\\")\u200b\\n\\n\u9996\u5148\u4ece\u603b\u4f53\u89d2\u5ea6\u8fdb\u884c\u5206\u6790\uff1aGPU\u901a\u8fc7HostInterface\uff0c\u63a5\u6536\u6765\u81ea\u4e3b\u673a\u7684\u6307\u4ee4\u4e0e\u6570\u636e\u3002\u4f7f\u7528\u4e00\u4e2aGiga Thread Engine\u6765\u7ba1\u7406\u6240\u6709\u6b63\u5728\u8fdb\u884c\u7684\u5de5\u4f5c\u3002GPU\u88ab\u5212\u5206\u6210\u591a\u4e2aGraphics Processing Cluster\uff08\u56fe\u5f62\u5904\u7406\u7c07\uff09\uff0c\u6bcf\u4e2aGPC\u62e5\u6709\u591a\u4e2aSM\u548c\u4e00\u4e2aRaster Engine(\u5149\u6805\u5316\u5f15\u64ce)\u3002\u5b83\u4eec\u5176\u4e2d\u6709\u5f88\u591a\u7684\u8fde\u63a5\uff0c\u6700\u663e\u8457\u7684\u662fCrossbar\uff0c\u5b83\u53ef\u4ee5\u5b9e\u73b0GPC\u4e4b\u95f4\u7684\u901a\u4fe1\u5e76\u6765\u8fde\u63a5\u5176\u5b83\u529f\u80fd\u6027\u6a21\u5757\uff08\u4f8b\u5982ROP\u6216\u5176\u4ed6\u5b50\u7cfb\u7edf\uff09\u3002\\n\\nRaster Engine\uff1a\u4e3b\u8981\u8d1f\u8d23\u5c06\u56fe\u5f62\u7ba1\u7ebf\u4e2d\u7684\u77e2\u91cf\u56fe\u5f62\u6570\u636e\uff08\u5982\u9876\u70b9\uff09\u8f6c\u6362\u4e3a\u50cf\u7d20\u4fe1\u606f\uff08\u5149\u6805\u56fe\u50cf\uff09\u7684\u90e8\u5206\u3002\\n\\nROP\uff08Raster Operations Pipeline\uff09\uff1a\u5149\u6805\u64cd\u4f5c\u5355\u5143\uff0c\u8d1f\u8d23\u5c06\u5149\u6805\u5316\u5f15\u64ce\u751f\u6210\u7684\u50cf\u7d20\u6570\u636e\u8fdb\u884c\u6700\u7ec8\u5904\u7406\uff0c\u5e76\u5c06\u5904\u7406\u540e\u7684\u50cf\u7d20\u8f93\u51fa\u5230\u5e27\u7f13\u51b2\u533a\u4e2d\uff0c\u6700\u7ec8\u751f\u6210\u53ef\u5728\u663e\u793a\u8bbe\u5907\u4e0a\u663e\u793a\u7684\u56fe\u50cf\u3002\\n\\n![Fermi SM](https://image.qifeng.xyz/202403061545043.png \\"Fermi SM\\")\\n\\n\u200d\\n\\n32 \u4e2a CUDA Core\uff08\u5206\u5728\u4e24\u6761 lane \u4e0a\uff0c\u6bcf\u6761\u5206\u522b\u662f 16 \u4e2a\uff09, \u6bcf\u4e2a CUDA Core \u91cc\u9762\u662f 1 \u4e2a\u5355\u7cbe\u6d6e\u70b9\u5355\u5143\uff08FPU\uff09\u548c 1 \u4e2a\u6574\u6570\u5355\u5143\uff08ALU\uff09\u3002\\n\\n1. SM\uff1a\u4ece G80 \u63d0\u51fa\u7684\u6982\u5ff5\uff0c\u4e2d\u6587\u79f0\u6d41\u5f0f\u591a\u5904\u7406\u5668\uff0c\u6838\u5fc3\u7ec4\u4ef6\u5305\u62ecCUDA\u6838\u5fc3\u3001\u5171\u4eab\u5185\u5b58\u3001\u5bc4\u5b58\u5668\u7b49\u3002SM\u5305\u542b\u8bb8\u591a\u4e3a\u7ebf\u7a0b\u6267\u884c\u6570\u5b66\u8fd0\u7b97\u7684Core\uff0c\u662f NVIDA \u7684\u6838\u5fc3\u3002\\n2. CUDA Core\uff1a\u5411\u91cf\u8fd0\u884c\u5355\u5143\\n\\n    * SP\uff08Streaming processor\uff09\uff1a\u6d41\u5f0f\u5904\u7406\u5668\u6700\u57fa\u672c\u7684\u5904\u7406\u5355\u5143\uff0cFermi \u67b6\u6784\u540e\uff0cSP\u88ab\u6539\u79f0\u4e3aCUDA Core\uff0c\u6700\u540e\u7ebf\u7a0b\u5177\u4f53\u7684\u6307\u4ee4\u548c\u4efb\u52a1\u90fd\u662f\u5728SP\u4e0a\u5904\u7406\u7684\u3002GPU\u8fdb\u884c\u5e76\u884c\u8ba1\u7b97\uff0c\u4e5f\u5c31\u662f\u5f88\u591a\u4e2aSP\u540c\u65f6\u505a\u5904\u7406\u3002\u4e00\u4e2aSP\u5bf9\u5e94\u4e00\u4e2a\u7ebf\u7a0b\u3002\\n    * FP32-FPU\uff1a\u5355\u7cbe\u5ea6\u6d6e\u70b9\u6570\u8fd0\u7b97\u5355\u5143\\n    * FP64-DPU\uff1a\u53cc\u7cbe\u5ea6\u6d6e\u70b9\u6570\u8fd0\u7b97\u5355\u5143\\n    * INT32-ALU\uff1a\u6574\u6570\u8fd0\u7b97\u5355\u5143\\n3. Special Function Units\uff1a\u7279\u6b8a\u51fd\u6570\u5355\u5143 SFU\uff0c\u8ba1\u7b97\u8d85\u8d8a\u51fd\u6570\u548c\u6570\u5b66\u51fd\u6570\uff0c\u4f8b\u5982\u4f59\u5f26\u51fd\u6570\uff0c\u4f46\u662f\u5b58\u5728\u7cbe\u5ea6\u635f\u5931\u3002\\n4. Warp Scheduler\uff1a\u7ebf\u7a0b\u675f\u8c03\u5ea6\u5668\uff0c\u7528\u4e8e\u5c06\u4e00\u6279\u6279\u7684Warp\u53d1\u9001\u7ed9\u7279\u5b9a\u7684\u8ba1\u7b97\u6838\u5fc3SP\u6267\u884c\u8ba1\u7b97\u3002\u4e00\u4e2aWarp\u753132\u4e2a\u7ebf\u7a0b\u7ec4\u6210\u3002\\n5. Dispatch Unit\uff1a\u6307\u4ee4\u5206\u53d1\u5355\u5143\uff0cDispatch Units\u8d1f\u8d23\u5c06Warp Scheduler\u7684\u6307\u4ee4\u9001\u5f80Core\u6267\u884c\uff08\u4e5f\u5c31\u662f\u4e0a\u9762\u7684SP\uff09\u3002\\n6. Load/Store\uff1a\u52a0\u8f7d/\u5b58\u50a8\u6a21\u5757\u3002\u8f85\u52a9\u4e00\u4e2aWarp\uff08\u7ebf\u7a0b\u7ec4\uff09\u4eceShare Memory\u6216\u663e\u5b58\u52a0\u8f7d(Load)\u6216\u5b58\u50a8(Store)\u6570\u636e\u3002\u8fd9\u4e2a\u5355\u5143\u5904\u7406\u64cd\u4f5c\u90fd\u662f\u5f02\u6b65\u7684\uff0c\u4e5f\u5c31\u662f\u8bf4\u5176\u4ed6\u5355\u5143\u5728\u9ad8\u901f\u5904\u7406\u6307\u4ee4\u7684\u65f6\u5019\uff0c\u5982\u679c\u9700\u8981\u52a0\u8f7d\u6216\u8005\u5199\u56de\u6570\u636e\uff0c\u5219\u4e0d\u4f1a\u5728\u8fd9\u91cc\u7b49\u5f85LD/ST\u8fd4\u56de\u6570\u636e\uff0c\u800c\u662f\u8df3\u8f6c\u6267\u884c\u5176\u4ed6\u6307\u4ee4\uff0c\u5f85LD/ST\u628a\u6570\u636e\u53d6\u5230\u6216\u8005\u5199\u56de\u4e4b\u540e\uff0c\u518d\u7ee7\u7eed\u6267\u884c\u9700\u8981\u8fd9\u4e9b\u6570\u636e\u7684\u540e\u7eed\u6307\u4ee4\u3002\\n7. Tex Unit\uff1a\u7eb9\u7406(texture)\u8bfb\u53d6\u5355\u5143,texture\u6307\u901a\u5e38\u7406\u89e3\u76841D/2D/3D\u7ed3\u6784\u6570\u636e\uff0c\u76f8\u90bb\u6570\u636e\u4e4b\u95f4\u5b58\u5728\u4e00\u5b9a\u5173\u7cfb\uff0c\u6216\u8005\u76f8\u90bb\u6570\u636e\u4e4b\u95f4\u9700\u8981\u8fdb\u884c\u76f8\u540c\u7684\u8fd0\u7b97\u3002\u5728\u4e00\u4e2a\u8fd0\u7b97\u5468\u671f\u6700\u591a\u53ef\u53d64\u4e2a\u91c7\u6837\u5668\uff0c\u8fd9\u65f6\u521a\u597d\u5582\u7ed9\u4e00\u4e2a\u7ebf\u7a0b\u675f\uff0c\u6bcf\u4e2aTexture Uint\u670916K\u7684Texture Cache\uff0c\u5e76\u4e14\u5728\u5f80\u4e0b\u6709L2 Cache\u7684\u652f\u6301\u3002\\n8. PolyMorph Engine\uff1a \u8d1f\u8d23\u5c5e\u6027\u88c5\u914d\uff08attribute Setup\uff09\u3001\u9876\u70b9\u62c9\u53d6\uff08Vertex Fetch\uff09\u3001\u66f2\u9762\u7ec6\u5206\u3001\u6805\u683c\u5316\uff08\u8fd9\u4e2a\u6a21\u5757\u53ef\u4ee5\u7406\u89e3\u4e13\u95e8\u5904\u7406\u9876\u70b9\u76f8\u5173\u7684\u4e1c\u897f\uff09\\n\\n    * Vertex Fetch\u6a21\u5757\uff1a\u9876\u70b9\u5904\u7406\u524d\u671f\u7684\u901a\u8fc7\u4e09\u89d2\u5f62\u7d22\u5f15\u53d6\u51fa\u4e09\u89d2\u5f62\u6570\u636e\u3002\\n    * Tesselator\u6a21\u5757\uff1a\u5bf9\u5e94\u7740DX11\u5f15\u5165\u7684\u65b0\u7279\u6027\u66f2\u9762\u7ec6\u5206\u3002\\n    * Stream Output\u6a21\u5757\uff1a\u5bf9\u5e94\u7740DX10\u5f15\u5165\u7684\u65b0\u7279\u6027Stream Output\u3002\\n    * Viewport Transform\u6a21\u5757\uff1a\u5bf9\u5e94\u7740\u9876\u70b9\u7684\u89c6\u53e3\u53d8\u6362\uff0c\u4e09\u89d2\u5f62\u4f1a\u88ab\u88c1\u526a\u51c6\u5907\u6805\u683c\u5316\u3002\\n    * Attribute Setup\u6a21\u5757\uff1a\u8d1f\u8d23\u9876\u70b9\u7684\u63d2\u503c\u8fd0\u7b97\u5e76\u8f93\u51fa\u7ed9\u540e\u7eed\u50cf\u7d20\u5904\u7406\u9636\u6bb5\u4f7f\u7528\u3002\\n9. Instruction Cache\uff1a\u6307\u4ee4\u7f13\u5b58\u3002\u5b58\u653e\u5c06\u8981\u6267\u884c\u7684\u6307\u4ee4\uff0c\u901a\u8fc7Dispatch Units\u586b\u88c5\u5230\u6bcf\u4e2a\u8fd0\u7b97\u6838\u5fc3\uff08Core\uff09\u8fdb\u884c\u8fd0\u7b97\u3002\\n10. Uniform Cache\uff1a\u7528\u4e8e\u63d0\u9ad8\u5bf9uniform\u53d8\u91cf\u8bbf\u95ee\u7684\u6548\u7387\u3002Uniform\u53d8\u91cf\u662f\u5728\u7740\u8272\u5668\u7a0b\u5e8f\u4e2d\u4f7f\u7528\u7684\u5e38\u91cf\uff0c\u5b83\u4eec\u5bf9\u4e8e\u4e00\u4e2a\u6e32\u67d3\u8c03\u7528\u4e2d\u7684\u6240\u6709\u9876\u70b9\u6216\u7247\u5143\u662f\u76f8\u540c\u7684\u3002\u8fd9\u4e9b\u53d8\u91cf\u5305\u62ec\u4f46\u4e0d\u9650\u4e8e\u77e9\u9635\uff08\u7528\u4e8e\u53d8\u6362\u6216\u6295\u5f71\uff09\u3001\u5149\u7167\u53c2\u6570\u3001\u6216\u8005\u5176\u4ed6\u5728\u7740\u8272\u5668\u6267\u884c\u671f\u95f4\u4e0d\u4f1a\u6539\u53d8\u7684\u5168\u5c40\u72b6\u6001\u4fe1\u606f\u3002\u540e\u7eed\u6f14\u5316\u4e3aconstant cache\u3002\\n11. Interconnect Network\uff1a\u662f\u4e00\u4e2a\u5173\u952e\u7ec4\u4ef6\uff0c\u5b83\u8d1f\u8d23\u5904\u7406GPU\u5185\u90e8\u5404\u4e2a\u90e8\u5206\u4e4b\u95f4\u7684\u6570\u636e\u4f20\u8f93\u548c\u901a\u4fe1\u3002\u8fd9\u4e2a\u7f51\u7edc\u4f7f\u5f97\u591a\u4e2a\u5904\u7406\u6838\u5fc3\uff08CUDA\u6838\u5fc3\uff09\u3001\u5185\u5b58\u63a7\u5236\u5668\u3001\u7f13\u5b58\u7cfb\u7edf\u7b49\u53ef\u4ee5\u9ad8\u6548\u5730\u4ea4\u6362\u6570\u636e\uff0c\u4ece\u800c\u63d0\u9ad8\u6574\u4f53\u7684\u5904\u7406\u901f\u5ea6\u548c\u6548\u7387\u3002\\n\\n#### 2.2.2 Kepler \u5f00\u666e\u52d2\u67b6\u6784\\n\\n![Kepler\u67b6\u6784](https://image.qifeng.xyz/202403061545878.png \\"Kepler\u67b6\u6784\\")![Kepler SMX](https://image.qifeng.xyz/202403061545686.png \\"Kepler SMX\\")\\n\\n\u76f8\u8f83\u4e8eFermi\u67b6\u6784\u7684\u53d8\u5316\u4e0d\u5927\u3002\\n\\n* SM\u6539\u540d\u6210\u4e86SMX\uff0c\u4f46\u662f\u6240\u4ee3\u8868\u7684\u6982\u5ff5\u6ca1\u6709\u5927\u53d8\u5316\uff1b\\n* \u5355\u4e2aSMX\u7684Cuda Core\u6570\u91cf\u4ece32\u4e2a\u589e\u52a0\u5230\u4e86192\u4e2a\uff08$4\\\\times3\\\\times16$\uff09\uff0c\u5f88\u5947\u602a\u7684\u6570\u5b57\u3002\\n* Kepler\u67b6\u6784\u5728\u786c\u4ef6\u4e0a\u76f4\u63a5\u6709\u53cc\u7cbe\u8fd0\u7b97\u5355\u5143\u7684\u67b6\u6784\uff1b\\n* \u63d0\u51fa GPU Direct \u6280\u672f\uff0c\u53ef\u4ee5\u7ed5\u8fc7 CPU/System Memory\uff0c\u5b8c\u6210\u4e0e\u672c\u673a\u5176\u4ed6 GPU \u6216\u8005\u5176\u4ed6\u673a\u5668 GPU \u7684\u76f4\u63a5\u6570\u636e\u4ea4\u6362\u3002\\n\\n#### 2.2.3 Maxwell \u9ea6\u514b\u65af\u97e6\u67b6\u6784\\n\\n![Maxwell  \u7535\u8def\u793a\u610f\u56fe](https://image.qifeng.xyz/202403061549614.jpg \\"Maxwell \u7535\u8def\u793a\u610f\u56fe\\")\\n\\n![Maxwell\u67b6\u6784](https://image.qifeng.xyz/202403061549757.png \\"Maxwell\u67b6\u6784\\")\\n\\n![Maxwll SMM\u793a\u610f\u56fe](https://image.qifeng.xyz/202403061545780.png \\"Maxwll SMM\u793a\u610f\u56fe\\")\\n\\nKepler\u67b6\u6784\u7684SMX\u8fc7\u4e8e\u5e9e\u6742\uff0c\u56e0\u6b64Maxwwll \u7684SMM\u780d\u6389\u4e86\u5f88\u591a\u5143\u4ef6\uff0c\u5c06\u7c7b\u4f3c\u4e8eFermi\u67b6\u6784\u7684\u56db\u4e2aSM\uff08Process Block\uff09\u62fc\u6210\u4e86\u4e00\u4e2aSMM\u3002\\n\\n#### 2.2.4 Pascal \u5e15\u65af\u5361\u67b6\u6784\\n\\n![Pascal\u67b6\u6784](https://image.qifeng.xyz/202403061550820.png \\"Pascal\u67b6\u6784\\")![Pascal SM](https://image.qifeng.xyz/202403061545005.png \\"Pascal SM\\")\u200b\\n\\n* \u5355\u4e2aSM\u53ea\u670964\u4e2aFP32 CUDA Cores\uff0c\u76f8\u6bd4Maxwell\u7684128\u548cKepler\u7684192\uff0c\u8fd9\u4e2a\u6570\u91cf\u8981\u5c11\u5f88\u591a\uff0c\u5e76\u4e1464\u4e2aCUDA Cores\u5206\u4e3a\u4e86\u4e24\u4e2a\u533a\u5757\uff1b\\n* Register File \u4fdd\u6301\u76f8\u540c\u5927\u5c0f\uff0c\u6bcf\u4e2a\u7ebf\u7a0b\u53ef\u4ee5\u4f7f\u7528\u66f4\u591a\u5bc4\u5b58\u5668\uff0c\u5355\u4e2aSM\u4e5f\u53ef\u4ee5\u5e76\u53d1\u66f4\u591a thread/warp/block\uff1b\\n* \u589e\u52a0 32\u4e2aFP64 CUDA Cores (DP Unit)\uff0cFP32 CUDA Core \u5177\u5907\u5904\u7406FP16\u7684\u80fd\u529b\u3002\\n* \u51fa\u73b0\u4e86TPC\u5c42\u6b21\\n* \u5f15\u5165\u4e86NVLink\\n\\n#### 2.2.5 Volta \u4f0f\u7279\u67b6\u6784\\n\\n![Volta \u67b6\u6784](https://image.qifeng.xyz/202403061545087.png \\"Volta \u67b6\u6784\\")![Volta SM](https://image.qifeng.xyz/202403061545020.png \\"Volta SM\\")\\n\\n\u6700\u663e\u8457\u7684\u53d8\u5316\u5c31\u662fcuda core\u88ab\u62c6\u5206\uff0c\u6574\u5f62\u8ba1\u7b97\u5355\u5143\u548cFP32\u8ba1\u7b97\u5355\u5143\u72ec\u7acb\u51fa\u73b0\u5728\u6d41\u6c34\u7ebf\u4e2d\u3002\u53ef\u4ee5\u5728\u4e00\u4e2a\u65f6\u949f\u5468\u671f\u5185\u540c\u65f6\u6267\u884c\u6574\u5f62\u8ba1\u7b97\u548c\u5355\u7cbe\u5ea6\u6d6e\u70b9\u6570\u8fd0\u7b97\u3002\u540c\u65f6\u76f8\u5bf9\u4e8ePascal\u6bcf\u4e2a\u533a\u5757\u53c8\u88ab\u4e00\u5206\u4e3a\u4e8c\u3002\u4e0d\u96be\u770b\u51fa\u5728\u51cf\u5c0f\u6bcf\u4e2a\u533a\u5757\u4ee5\u53ca\u6bcf\u4e2aSM\u8fd0\u7b97\u5355\u5143\u7684\u6570\u91cf\uff0c\u540c\u65f6\u589e\u52a0SM\u7684\u6570\u91cf\u3002\\n\\n\u6700\u91cd\u8981\u7684\u662f\u5f15\u5165\u4e86\u5f20\u91cf\u6838\u5fc3(Tensor Core)\u3002\\n\\n#### 2.2.6 Turing \u56fe\u7075\u67b6\u6784\\n\\n![Turing \u67b6\u6784](https://image.qifeng.xyz/202403061551818.png \\"Turing \u67b6\u6784\\")![Turing SM](https://image.qifeng.xyz/202403061545455.png \\"Turing SM\\")\u9664\u4e86\u5728Tensor Core\u4e2d\u5f15\u5165int 8 \u548cint4\uff0c\u4ee5\u53ca\u780d\u6389FP64\u5355\u5143\u5916\u53d8\u52a8\u4e0d\u5927\uff0c\u4e3b\u8981\u96c6\u4e2d\u5728\u6e32\u67d3\u7ba1\u7ebf\u548c\u65b0\u52a0\u7684\u8fd9\u4e2a RT Core \u5149\u7ebf\u8ffd\u8e2a\u80fd\u529b\u4e0a\u3002\\n\\n#### 2.2.7 Ampere \u5b89\u57f9\u67b6\u6784\\n\\n![Ampere \u67b6\u6784\u56fe](https://image.qifeng.xyz/202403061552794.png \\"Ampere \u67b6\u6784\u56fe\\")\\n\\n![Ampere SM\u7ed3\u6784](https://image.qifeng.xyz/202403061552558.png \\"Ampere SM\u7ed3\u6784\\")\\n\\n\u589e\u52a0\u4e86FP64\u5355\u5143\uff0cTensor Core\u53d8\u4e3a\u539f\u6765\u7684\u4e00\u534a\uff0c\u4f46\u662f\u8ba1\u7b97\u80fd\u529b\u5176\u5b9e\u589e\u5f3a\u4e86\uff0c\u5355\u4e2a\u65f6\u949f\u5468\u671f\u541e\u5410\u91cf\u91cf\u63d0\u9ad8\u4e86\uff0c\u540c\u65f6\u5f15\u5165\u4e86\u7ed3\u6784\u5316\u7a00\u758f\u80fd\u529b\u3002\u589e\u52a0\u4e86\u591a\u5b9e\u4f8bGPU\uff08Multi-Instance GPU\uff09\uff0c\u5c06\u5355\u4e2aA100GPU\u5212\u5206\u4e3a\u591a\u8fbe\u4e03\u4e2a\u72ec\u7acbGPU\uff0c\u4e3a\u4e0d\u540c\u4efb\u52a1\u63d0\u4f9b\u4e0d\u540c\u7b97\u529b\u3002\\n\\n\u5f15\u5165\u4e86TF32 \u548cBF16\u7684\u652f\u6301\uff1a\\n\\n![image](https://image.qifeng.xyz/202403061545369.png)\\n\\n#### 2.2.8 Hopper \u8d6b\u67cf\u67b6\u6784\\n\\n![Hopper \u67b6\u6784](https://image.qifeng.xyz/202403061545299.png \\"Hopper \u67b6\u6784\\")![Hopper SM](https://image.qifeng.xyz/202403061546471.png \\"Hopper SM\\")\\n\\n\u200b**SM \u7ed3\u6784\uff1a**\\n\\n* 4 \u4e2a Warp Scheduler\uff0c4 \u4e2a Dispatch Unit\uff08\u4e0e A100 \u4e00\u81f4\uff09\\n* 128 \u4e2a FP32 Core\uff084 * 32\uff09\uff08\u76f8\u6bd4 A100 \u7ffb\u500d\uff09\\n* 64 \u4e2a INT32 Core\uff084 * 16\uff09\uff08\u4e0e A100 \u4e00\u81f4\uff09\\n* 64 \u4e2a FP64 Core\uff084 * 16\uff09\uff08\u76f8\u6bd4 A100 \u7ffb\u500d\uff09\\n* 4 \u4e2a TensorCore\uff084 * 1\uff09\\n* 32 \u4e2a LD/ST Unit\uff084 * 8\uff09\uff08\u4e0e A100 \u4e00\u81f4\uff09\\n* 16 \u4e2a SFU\uff084 * 4\uff09\uff08\u4e0e A100 \u4e00\u81f4\uff09\\n* \u76f8\u6bd4 A100 \u589e\u52a0\u4e86\u4e00\u4e2a Tensor Memory Accelerator\\n\\n**Process Block\uff1a**\\n\\n* 1 \u4e2a Warp Scheduler\uff0c1 \u4e2a Dispatch Unit\uff08\u4e0e A100 \u4e00\u81f4\uff09\\n* 32 \u4e2a FP32 Core\uff08\u76f8\u6bd4 A100 \u7ffb\u500d\uff09\\n* 16 \u4e2a INT32 Core\uff08\u4e0e A100 \u4e00\u81f4\uff09\\n* 16 \u4e2a FP64 Core\uff08\u76f8\u6bd4 A100 \u7ffb\u500d\uff09\\n* 1 \u4e2a TensorCore\\n* 8 \u4e2a LD/ST Unit\uff08\u4e0e A100 \u4e00\u81f4\uff09\\n* 4 \u4e2a SFU\uff08\u4e0e A100 \u4e00\u81f4\uff09\\n\\n\u5f15\u5165\u4e86\u7ebf\u7a0b\u5757\u7c07\uff0c\u7c07\u662f\u4e00\u7ec4\u4fdd\u8bc1\u53ef\u4ee5\u5e76\u53d1\u8c03\u5ea6\u7684\u7ebf\u7a0b\u5757\uff0c\u652f\u6301\u8de8\u591a\u4e2a SM \u7684\u7ebf\u7a0b\u8fdb\u884c\u9ad8\u6548\u534f\u4f5c\u548c\u6570\u636e\u5171\u4eab\u3002\u7c07\u8fd8\u53ef\u4ee5\u66f4\u9ad8\u6548\u5730\u534f\u540c\u9a71\u52a8Tensor \u5185\u5b58\u52a0\u901f\u5668\u548c Tensor Core \u7b49\u5f02\u6b65\u5355\u5143\u3002\u5728\u7269\u7406\u5c42\u6b21\u4e0a\u5bf9\u5e94\u7684\u662fGPC,\u53ef\u4ee5\u76f4\u63a5\u8bbf\u95ee\u540c\u7c07\u5185\u5176\u4ed6SM\u7684\u5171\u4eab\u5185\u5b58\u800c\u4e0d\u7528\u7ecf\u8fc7\u663e\u5b58\u4e2d\u8f6c\u3002\\n\\n![\u7ebf\u7a0b\u5c42\u6b21](https://image.qifeng.xyz/202403061546643.png \\"\u7ebf\u7a0b\u5c42\u6b21\\")![](https://image.qifeng.xyz/202403061553946.png)\u200b\\n\\n### 2.3 TensorCore\\n\\n\u77e9\u9635\u4e58\u6cd5\u5728\u8fdb\u884c\u884c\u5217\u76f8\u4e58\u65f6\u9700\u8981\u9010\u5143\u7d20\u7684\u76f8\u4e58\u7d2f\u52a0\u3002\u8fd9\u4e2a\u8fc7\u7a0b\u53ef\u4ee5\u4f7f\u7528\u4e58\u79ef\u7d2f\u52a0\u6307\u4ee4FMA\uff08Fused Multiply\u2013accumulate operation\uff09\u5b8c\u6210\u3002\\n\\n\u6240\u8c13\u7684FMA\u6307\u4ee4\u5c31\u662f\uff1a$a=a+(b\\\\times c)$\u4e0b\u56fe\u793a\u4f8b\u9700\u8981$5\\\\times 5\\\\times 5$\u6b21FMA \u5b8c\u6210\u3002\\n\\n![\u77e9\u9635\u4e58\u6cd5](https://image.qifeng.xyz/202403061546301.png \\"\u77e9\u9635\u4e58\u6cd5\\")\\n\\n\u6bcf\u4e2a Tensor Core \u6bcf\u5468\u671f\u80fd\u6267\u884c $4\\\\times4\\\\times4$ GEMM\uff0c64 \u4e2a FMA\u3002\u6267\u884c\u8fd0\u7b97 D=AB+C\uff0c\u5176\u4e2dA\u3001B\u3001C \u548c D\u662f$4\\\\times4$ \u77e9\u9635\u3002\u77e9\u9635\u4e58\u6cd5\u8f93\u5165 A \u548c B \u662f FP16 \u77e9\u9635\uff0c\u800c\u7d2f\u52a0\u77e9\u9635 C \u548c D \u53ef\u4ee5\u662f FP16\u6216 FP32 \u77e9\u9635\u3002\\n\\n![image](https://image.qifeng.xyz/202403061546129.png)\u200b\\n\\nTensor Core\u6267\u884c\u878d\u5408\u4e58\u6cd5\u52a0\u6cd5\uff0c\u5176\u4e2d\u4e24\u4e2a$4\\\\times4$FP16\u77e9\u9635\u76f8\u4e58\uff0c\u7136\u540e\u5c06\u7ed3\u679c\u6dfb\u52a0\u5230$4\\\\times4$ FP16\u6216FP32\u77e9\u9635\u4e2d\uff0c\u6700\u7ec8\u8f93\u51fa\u65b0\u7684$4\\\\times4$ FP16\u6216FP32\u77e9\u9635\u3002\\n\\n![image](https://image.qifeng.xyz/202403061546753.png)\u6bcf\u4e2a Tensor Core \u6bcf\u4e2a\u65f6\u949f\u6267\u884c 64 \u4e2a FP32 FMA \u6df7\u5408\u7cbe\u5ea6\u8fd0\u7b97\uff0cSM\u4e2d8\u4e2a Tensor Core\uff0c\u6bcf\u4e2a\u65f6\u949f\u5468\u671f\u5185\u603b\u5171\u6267\u884c 512 \u4e2a\u6d6e\u70b9\u8fd0\u7b97\u3002\\n\\n\u56e0\u6b64\u5728 AI \u5e94\u7528\u4e2d\uff0c Volta V100 GPU\u7684\u541e\u5410\u91cf\u4e0ePascal P100 GPU\u76f8\u6bd4\uff0c\u6bcf\u4e2a SM \u7684 AI \u541e\u5410\u91cf\u589e\u52a0\u4e86 8 \u500d\uff0c\u603b\u5171\u589e\u52a0\u4e8612\u500d\u3002\\n\\n![\u56fe\u72472](https://image.qifeng.xyz/202403061546556.gif)\u200b\\n\\n### 2.4 NVlink\\n\\nNVLink\uff1a\u82f1\u4f1f\u8fbe\uff08NVIDIA\uff09\u5f00\u53d1\u5e76\u63a8\u51fa\u7684\u4e00\u79cd\u603b\u7ebf\u53ca\u5176\u901a\u4fe1\u534f\u8bae\u3002NVLink\u91c7\u7528\u70b9\u5bf9\u70b9\u7ed3\u6784\u3001\u4e32\u5217\u4f20\u8f93\uff0c\u7528\u4e8e\u4e2d\u592e\u5904\u7406\u5668\uff08CPU\uff09\u4e0e\u56fe\u5f62\u5904\u7406\u5668\uff08GPU\uff09\u4e4b\u95f4\u7684\u8fde\u63a5\uff0c\u4e5f\u53ef\u7528\u4e8e\u591a\u4e2a\u56fe\u5f62\u5904\u7406\u5668\uff08GPU\uff09\u4e4b\u95f4\u7684\u76f8\u4e92\u8fde\u63a5\u3002  \\nNVSwitch\uff1a\u662f\u4e00\u79cd\u9ad8\u901f\u4e92\u8fde\u6280\u672f\uff0c\u540c\u65f6\u4f5c\u4e3a\u4e00\u5757\u72ec\u7acb\u7684 NVLink \u82af\u7247\uff0c\u5176\u63d0\u4f9b\u4e86\u9ad8\u8fbe18\u8def NVLink \u7684\u63a5\u53e3\uff0c\u53ef\u4ee5\u5728\u591a\u4e2a GPU \u4e4b\u95f4\u5b9e\u73b0\u9ad8\u901f\u6570\u636e\u4f20\u8f93\u3002\\n\\nNCCL / HCCL\uff1a GPU/NPU \u901a\u4fe1\u4f18\u5316\u5e93\uff0c\u652f\u6301\u96c6\u4e2d\u5f0f\u901a\u4fe1\u3002\\n\\n\u200d\\n\\n## 3 \u53c2\u8003\u8d44\u6599\\n\\n[1] [chenzomi12/DeepLearningSystem: Deep Learning System core principles introduction. (github.com)](https://github.com/chenzomi12/DeepLearningSystem)\\n\\n[2][TransformAndLighting.pdf (nvidia.com)](https://developer.download.nvidia.com/assets/gamedev/docs/TransformAndLighting.pdf)\\n\\n[3] [\u6df1\u5165GPU\u786c\u4ef6\u67b6\u6784\u53ca\u8fd0\u884c\u673a\u5236 - 0\u5411\u5f800 - \u535a\u5ba2\u56ed (cnblogs.com)](https://www.cnblogs.com/timlly/p/11471507.html)\\n\\n[4][NVIDIA GPU\u6027\u80fd\u4f18\u5316\u57fa\u7840 - \u77e5\u4e4e (zhihu.com)](https://zhuanlan.zhihu.com/p/577412348)\\n\\n[5][1509.02308.pdf (arxiv.org)](https://arxiv.org/pdf/1509.02308.pdf)\\n\\n[6] [Life of a triangle - NVIDIA&apos;s logical pipeline | NVIDIA Developer](https://developer.nvidia.com/content/life-triangle-nvidias-logical-pipeline)\\n\\n[7] [GPU\u67b6\u6784\u548c\u6e32\u67d3 - \u77e5\u4e4e (zhihu.com)](https://zhuanlan.zhihu.com/p/441610596)\\n\\n[8][NVIDIA GPU \u67b6\u6784\u6f14\u8fdb | Chenfan Blog (jcf94.com)](https://jcf94.com/2020/05/24/2020-05-24-nvidia-arch/)\\n\\n\u200d"}]}}')}}]);